window.__QUIZ_SUBJECT__=[{"id": "objective>Marketing>2019>1", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "DISTRIBUTION : FUNCTIONS", "question": "One of the functions of a small retailer is to", "images": [], "options": {"A": "break goods into small units.", "B": "sell goods in large quantities.", "C": "grant credit to producers.", "D": "sell goods to the final consumers."}, "answer": "A", "explanation": "A small retailer's function is to break goods into small units. This is because they serve the end consumers who usually buy in small quantities. This process is also known as 'breaking bulk', which is a key function of retailing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>2", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "TRANSPORTATION : MEANING,MODE, CHOICE AND IMPORTANCE", "question": "An importance of transportation to a marketer is that it", "images": [], "options": {"A": "reduces cost of production.", "B": "increases the price of goods.", "C": "increases the efficiency in distribution.", "D": "reduces the distribution cost."}, "answer": "C", "explanation": "Transportation increases the efficiency in distribution. It allows goods to be moved from the place of production to the place of consumption, making them available to consumers in different locations. This is a key aspect of the distribution process in marketing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>3", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "WAREHOUSING : MEANING, TYPES AND DEFINITIONS", "question": "Which of the following is a function of warehousing?", "images": [], "options": {"A": "Keeping and making goods available when required", "B": "Hoarding of goods to increase price", "C": "Making goods available to final consumers", "D": "Storing of small units of products"}, "answer": "A", "explanation": "The function of warehousing is to keep and make goods available when required. Warehouses store goods until they are needed by the market. This ensures a steady supply of goods, preventing shortages and helping to maintain price stability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>4", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL MARKETING : GUIDING RULES AND REGULATIONS", "question": "One of the rules that guides international marketing is", "images": [], "options": {"A": "import restriction", "B": "memorandum of association", "C": "company's annual report", "D": "articles of association"}, "answer": "A", "explanation": "International marketing is guided by various rules and regulations, one of which is import restriction. Import restrictions are limitations put on the quantity of a certain good that can be imported during a specific period. This is not related to the memorandum of association, company's annual report, or articles of association, which are all internal company documents.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>5", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "ICT IN MARKETING : USES, ETHICS AND ABUSES", "question": "A challenge of marketing financial products online is that it is prone to", "images": [], "options": {"A": "identity theft.", "B": "unsolicited advertisements.", "C": "mass promotion.", "D": "unsolicited mails."}, "answer": "A", "explanation": "Marketing financial products online is indeed prone to identity theft. This is because financial products often require the exchange of sensitive personal and financial information, which can be intercepted by malicious parties. Unsolicited advertisements, mass promotion, and unsolicited mails can be annoying but they do not pose the same level of risk as identity theft.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>6", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL MARKETING : INFLUENCING FACTORS", "question": "Which of the following entry modes in international marketing would be suitable for expensive projects?", "images": [], "options": {"A": "Direct investment", "B": "Joint venture", "C": "Exporting", "D": "Franchising"}, "answer": "B", "explanation": "For expensive projects, a joint venture would be a suitable entry mode in international marketing. This is because a joint venture allows two or more parties to share the risks and costs associated with a project, making it a more feasible option for expensive projects. Direct investment, exporting, and franchising are other entry modes, but they may not be as suitable for expensive projects due to the higher risks and costs involved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>7", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "PRODUCTS : PRODUCT DESIGN", "question": "A function of packaging is to", "images": [], "options": {"A": "improve product's quality", "B": "reduce competition", "C": "protect the product", "D": "prevent adulteration"}, "answer": "C", "explanation": "One of the primary functions of packaging is to protect the product from damage during transportation, from dirt and contamination, and from humidity and temperature changes. It does not directly improve the product's quality, reduce competition, or prevent adulteration.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>8", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "The orientation that assumes that consumers would only buy when persuaded with aggressive advertisement is", "images": [], "options": {"A": "selling concept", "B": "product concept", "C": "production concept", "D": "marketing concept"}, "answer": "A", "explanation": "The selling concept assumes that consumers will either not buy enough of the firm's products on their own or will not buy at all unless the firm undertakes a large-scale selling and promotion effort. It is characterized by aggressive advertising and persuasive selling techniques.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>9", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : MEANING OF MARKETING MIX", "question": "An element in the marketing mix is", "images": [], "options": {"A": "propaganda", "B": "publicity", "C": "product", "D": "packaging"}, "answer": "C", "explanation": "The marketing mix, also known as the 4 P's of marketing, includes Product, Price, Place, and Promotion. Product refers to what you are selling, including all of the features, advantages and benefits that your customers can enjoy from buying your goods or services. Propaganda and packaging are not considered as elements of the marketing mix.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>10", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKETING CONCEPTS : MEANING", "question": "Which of the following is an attribute of marketing concept? Consumers", "images": [], "options": {"A": "are considered to be always right", "B": "prefer quality products", "C": "would buy cheap products", "D": "prefer goods that are highly advertised"}, "answer": "A", "explanation": "The marketing concept is a business philosophy that holds the key to achieving organizational goals consists of the company being more effective than competitors in creating, delivering, and communicating superior customer value to its chosen target markets. It emphasizes that the company should always consider the needs and wants of the consumers. Therefore, the statement 'Consumers are considered to be always right' is an attribute of the marketing concept.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>11", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MERCHANDISING : MEANING", "question": "Merchandising is best suited for", "images": [], "options": {"A": "consumer goods", "B": "primary products", "C": "industrial services", "D": "organizational products"}, "answer": "A", "explanation": "Merchandising refers to the variety of products available for sale and the display of those products in such a way that it stimulates interest and entices customers to make a purchase. It is best suited for consumer goods as these are the products that are sold directly to consumers for their personal use.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>12", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "Which channel of distribution would a producer of tomato paste in Kano use to reach a target market in Asaa?", "images": [], "options": {"A": "Producer → Agent → Consumer", "B": "Producer → Wholesaler → Consumer", "C": "Producer → Retailer → Consumer", "D": "Producer → Wholesaler → Retailer → Consumer"}, "answer": "D", "explanation": "The channel of distribution refers to the path or route along which goods move from producers to ultimate consumers. For a producer of tomato paste in Kano to reach a target market in Asaa, the most likely channel of distribution would be 'Producer → Wholesaler → Retailer → Consumer'. This is because the producer would sell to the wholesaler who would then sell to the retailer, and finally, the retailer would sell to the consumer. This channel is often used for products that are sold in small quantities to consumers, such as tomato paste.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>13", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "WAREHOUSING : MEANING, TYPES AND DEFINITIONS", "question": "A disadvantage of warehousing is that it", "images": [], "options": {"A": "makes goods available when needed", "B": "protects goods from damage", "C": "encourages hoarding of goods to create scarcity", "D": "prevents a reduction in the quality of goods"}, "answer": "C", "explanation": "Warehousing is the act of storing goods that will be sold or distributed later. While warehousing is generally seen as a positive for businesses because it allows them to store goods and manage inventory, it can also encourage hoarding of goods to create scarcity. This is because when goods are stored in a warehouse, they are not available for immediate sale or distribution, which can create a sense of scarcity and drive up prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>14", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "ICT IN MARKETING : E-MARKETING - MEANING, IMPORTANCE", "question": "Electronic marketing is made possible through network of", "images": [], "options": {"A": "computers", "B": "consumers groups", "C": "manufacturers", "D": "advertising media"}, "answer": "A", "explanation": "Electronic marketing, also known as e-marketing, digital marketing, or online marketing, is the process of marketing a product or service using the internet. It is made possible through a network of computers. This network allows businesses to reach a global audience, track consumer behavior, and deliver personalized content.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>15", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "TRANSPORTATION : MEANING,MODE, CHOICE AND IMPORTANCE", "question": "Which of the following modes of transportation ensures the supply of gas in all-weather conditions?", "images": [], "options": {"A": "Trailers", "B": "Pipeline", "C": "Aeroplane", "D": "Train"}, "answer": "B", "explanation": "The supply of gas in all-weather conditions is ensured by pipelines. Pipelines are a mode of transportation that is used to move goods such as oil, gas, and water over long distances. They are not affected by weather conditions and can operate continuously, making them the most reliable mode of transportation for these types of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>16", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : SELLING AND BARGAINING SKILLS", "question": "A skill required by an entrepreneur for successful bargaining is", "images": [], "options": {"A": "interpersonal skill", "B": "leadership skill", "C": "accounting skill", "D": "administrative skill"}, "answer": "A", "explanation": "Successful bargaining requires effective communication, understanding of the other party's needs and interests, and the ability to build a good relationship with them. These are all aspects of interpersonal skills. Therefore, interpersonal skill is a key skill required by an entrepreneur for successful bargaining.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>17", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : FACTORS AFFECTING LOCATION OF A MARKET OUTLET", "question": "Which of the following factors affects the location of a retail outlet?", "images": [], "options": {"A": "Government policy", "B": "Weather condition", "C": "Company's goodwill", "D": "Product quality"}, "answer": "A", "explanation": "The location of a retail outlet can be significantly affected by government policies. For instance, zoning laws can dictate where certain types of businesses can be located. Additionally, tax incentives or subsidies might encourage businesses to locate in certain areas. Therefore, government policy is a factor that affects the location of a retail outlet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>18", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKETS : MEANING", "question": "The shop that offers a range of grocery items is a", "images": [], "options": {"A": "specialty store.", "B": "depot.", "C": "supermarket.", "D": "discount store."}, "answer": "C", "explanation": "A supermarket is a large self-service shop selling foods and household goods. It offers a range of grocery items, among other products. Therefore, the shop that offers a range of grocery items is a supermarket.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>19", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : MEANING OF ENTREPRENEURSHIP", "question": "The reward for an entrepreneur is", "images": [], "options": {"A": "a fee", "B": "profit", "C": "salary", "D": "a commission"}, "answer": "B", "explanation": "The reward for an entrepreneur is profit. An entrepreneur invests capital in a business at a risk of loss and aims to earn profit. This profit serves as a reward for the risk taken and the initiatives made. Therefore, the correct answer is 'profit'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>20", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : MARKET FACILITATORS - MEANING, TYPES AND ROLES", "question": "Which of the following marketing facilitators provide financial services?", "images": [], "options": {"A": "Advertising agencies", "B": "Savings and loans companies", "C": "Clearing and forwarding companies", "D": "Legal firms"}, "answer": "B", "explanation": "Savings and loans companies provide financial services. They accept savings and time deposits and lend out these funds to earn interest. They play a crucial role in the marketing process by providing the necessary funds for businesses to operate and expand. Therefore, the correct answer is 'Savings and loans companies'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>21", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "The systematic analysis of a problem with the aim of improving decision making on sales is marketing", "images": [], "options": {"A": "research", "B": "planning", "C": "concept", "D": "forecasting"}, "answer": "A", "explanation": "The systematic analysis of a problem with the aim of improving decision making on sales is marketing research. Marketing research involves the identification, collection, analysis, dissemination, and use of information for the purpose of improving decision making related to the identification and solution of problems and opportunities in marketing. Therefore, the correct answer is 'research'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>22", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "PRICING : STRATEGIES", "question": "The pricing approach that is based on what rival companies are charging is", "images": [], "options": {"A": "cost-oriented approach", "B": "demand-oriented approach", "C": "competitor-oriented approach", "D": "value-oriented approach"}, "answer": "C", "explanation": "The pricing approach that is based on what rival companies are charging is known as the competitor-oriented approach. This approach involves setting prices based on what the competition is charging, with the belief that this will lead to optimal market share and profitability.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>23", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : UTILIZATION OF FEEDBACK", "question": "Feedback obtained from marketing research on consumer's needs would be used to", "images": [], "options": {"A": "reduce production cost.", "B": "change product features.", "C": "improve sales force remuneration.", "D": "improve inventory control."}, "answer": "B", "explanation": "Feedback obtained from marketing research on consumer's needs would be used to change product features. This is because the main purpose of marketing research is to understand the needs and preferences of the consumers. Once these needs are understood, the product features can be modified to meet these needs, thereby increasing customer satisfaction and sales.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>24", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : REASONS FOR MARKETING PLANNING AND RESEARCH", "question": "An importance of marketing research is that it", "images": [], "options": {"A": "reduces the risk involved in decision making.", "B": "increases the cost of production.", "C": "increases the risk involve in decision making.", "D": "reduces the quality of products."}, "answer": "A", "explanation": "An importance of marketing research is that it reduces the risk involved in decision making. By providing valuable information about the market, customers, competitors, and other factors, marketing research helps businesses make informed decisions. This reduces the risk of making wrong decisions that could lead to business failure.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>25", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "INTRODUCTION TO MARKETING : FUNCTIONS", "question": "Which of the following activities is a function of marketing?", "images": [], "options": {"A": "Provision of finance", "B": "Absorption of risk", "C": "Facilitation of exchange", "D": "Production of goods"}, "answer": "C", "explanation": "Marketing involves a range of activities, one of which is the facilitation of exchange. This involves creating, communicating, delivering, and exchanging offerings that have value for customers, clients, partners, and society at large. It does not directly involve the provision of finance, absorption of risk, or production of goods, although these activities may be indirectly related to marketing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>26", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : MARKET FACILITATORS - MEANING, TYPES AND ROLES", "question": "An individual or organization that enhances business activities but do not participate in the business is a", "images": [], "options": {"A": "distributor", "B": "seller", "C": "marketer", "D": "facilitator"}, "answer": "D", "explanation": "A facilitator in a business context is an individual or organization that enables business activities to occur more smoothly or efficiently but does not directly participate in the business. They provide services that help businesses operate more effectively, such as consulting, training, or providing specialized resources or technology. Distributors, sellers, and marketers are all direct participants in a business.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>27", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKETS : CLASSIFICATION", "question": "A market with many buyers compared to suppliers is an example of", "images": [], "options": {"A": "government market", "B": "reseller market", "C": "consumer market", "D": "industrial market"}, "answer": "C", "explanation": "Consumer market is market dominated by products and services designed for the general consumer. It is a market with many buyers compared to suppliers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>28", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : INFLUECING FACTORS", "question": "In the consumer buying-decision process, an influencing factor that includes age and occupation is", "images": [], "options": {"A": "personal factor.", "B": "social factor.", "C": "cultural factor.", "D": "psychological factor."}, "answer": "A", "explanation": "In the consumer buying-decision process, personal factors include aspects such as age, occupation, lifestyle, personality, and self-concept. These factors influence the individual's decision-making process when purchasing a product or service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>29", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "At what stage in the buying-decision process does a consumer collect information about a product?", "images": [], "options": {"A": "Need recognition stage", "B": "Alternative search stage", "C": "Post-purchase decision", "D": "Purchase decision"}, "answer": "B", "explanation": "In the buying-decision process, the consumer collects information about a product during the 'Alternative search stage'. This is the stage where the consumer is aware of a need or problem and starts to search for more information about the possible solutions or products that can satisfy this need.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>30", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : FACTORS AFFECTING MARKETING ENVIRONMENT", "question": "An element in a company's economic environment is", "images": [], "options": {"A": "personal lifestyle", "B": "family members", "C": "technological innovation", "D": "inflation rate"}, "answer": "D", "explanation": "An element in a company's economic environment is the 'inflation rate'. The economic environment of a business includes all economic factors that affect consumer buying power and spending patterns. This includes factors such as inflation rate, unemployment rate, and economic growth rate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>31", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "PRICING : PRICE DETERMINANTS", "question": "Which of the following factors is considered when determining the price of a product by a manufacturer?", "images": [], "options": {"A": "Quality of the goods", "B": "After-sales services", "C": "Stock turnover", "D": "Channels of distribution"}, "answer": "A", "explanation": "The quality of goods is a key factor considered when determining the price of a product by a manufacturer. The higher the quality of a product, the higher the price it can command in the market. This is because quality products are often associated with durability, reliability, and superior performance, which consumers are willing to pay a premium for.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>32", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "An advertising medium that practically demonstrates the use of a product is the", "images": [], "options": {"A": "television", "B": "magazine", "C": "newspaper", "D": "radio"}, "answer": "A", "explanation": "Television is an advertising medium that practically demonstrates the use of a product. This is because television allows for visual and audio representation of the product, showing how it is used in real-life situations. This can be more effective than other mediums like radio, newspaper, and magazine that primarily rely on audio or visual alone.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>33", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "A short-term incentive used to encourage consumers to buy a product is", "images": [], "options": {"A": "advertising.", "B": "public relations.", "C": "sales promotion.", "D": "publicity."}, "answer": "C", "explanation": "Sales promotion is a short-term incentive used to encourage consumers to buy a product. Sales promotions include tactics like discounts, coupons, buy one get one free offers, and other incentives designed to stimulate immediate purchase.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>34", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "ADVERTISING : FUNCTIONS", "question": "Advertising aimed only at giving facts about a product is", "images": [], "options": {"A": "competitive advertising", "B": "persuasive advertising", "C": "informative advertising", "D": "direct advertising"}, "answer": "C", "explanation": "Informative advertising is a type of advertising that is used to inform consumers about a product, its features, and its benefits. It is often used to introduce a new product or to promote a product that is not well-known. This type of advertising is focused on providing factual information to consumers, rather than trying to persuade them to buy the product or comparing it to other products on the market.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>35", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "PRODUCTS : CLASSIFICATION", "question": "Which of the following food items is a primary product?", "images": [], "options": {"A": "Frozen fish", "B": "Fresh fish", "C": "Smoked fish", "D": "Dry fish"}, "answer": "B", "explanation": "A primary product is a product that is in its raw or natural state, and has not been processed or transformed in any way. Fresh fish is a primary product because it has not been processed or transformed in any way. Frozen fish, smoked fish, and dry fish are all processed products, as they have been transformed from their natural state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>36", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "Sales promotion is", "images": [], "options": {"A": "selling of goods to the consumers.", "B": "predicting quantity of goods to be demanded.", "C": "stimulating demand through short term incentives", "D": "making goods available to consumers"}, "answer": "C", "explanation": "Sales promotion refers to the activities that are undertaken to boost the sales of a product or service. This can include a variety of different strategies, such as offering discounts or special offers, providing free samples, or running competitions. The aim of these activities is to stimulate demand for the product or service in the short term.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>37", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "The need and ability to pay for a product is", "images": [], "options": {"A": "demand.", "B": "supply.", "C": "sales.", "D": "transaction."}, "answer": "A", "explanation": "The need and ability to pay for a product is referred to as 'demand'. In economics, demand is the quantity of a good that consumers are willing and able to purchase at various prices during a given period of time. The relationship between price and quantity demanded is also known as the demand curve.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>38", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "PRODUCTS : CLASSIFICATION", "question": "Tubers of yam offered by a farmer for sales is an example of a", "images": [], "options": {"A": "secondary product.", "B": "manufactured product.", "C": "primary product.", "D": "processed product."}, "answer": "C", "explanation": "Tubers of yam offered by a farmer for sales is an example of a 'primary product'. Primary products are goods that are available from cultivating raw materials without a manufacturing process. In this case, yam tubers are harvested directly from the farm, making them a primary product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2019>39", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKETS : CLASSIFICATION", "question": "A market where specialist are needed before purchase decision is made is", "images": [], "options": {"A": "consumer market.", "B": "industrial market.", "C": "reseller market.", "D": "commodity market."}, "answer": "B", "explanation": "A market where specialists are needed before purchase decision is made is an 'industrial market'. Industrial markets deal with the commercial transactions of goods and services between businesses, not consumers. These goods and services are often complex and require specialist knowledge to make an informed purchase decision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2019>40", "subject": "Marketing", "year": "2019", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : MEANING OF MARKETING MIX", "question": "The set of controllable variables used to influence consumers is", "images": [], "options": {"A": "promotional mix.", "B": "communication mix.", "C": "marketing mix.", "D": "product mix."}, "answer": "C", "explanation": "The marketing mix is a business tool used in marketing and by marketers. The marketing mix is often crucial when determining a product or brand's offer, and is often associated with the four P's: price, product, promotion, and place. Therefore, it is the set of controllable variables used to influence consumers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>1", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "INTRODUCTION TO MARKETING : MEANING OF MARKETING", "question": "Marketing is the", "images": [], "options": {"A": "buying and selling of goods and services", "B": "buying,selling and distribution of goods and services", "C": "identification and satisfaction of consumer's needs at a profit", "D": "distribution and transportation of goods at a profit"}, "answer": "C", "explanation": "Marketing is the process of identifying, anticipating and satisfying customers' needs and wants profitably. It involves activities such as market research, product development, distribution, communication and customer service. Therefore, the option 'identification and satisfaction of consumer's needs at a profit' is the most accurate definition of marketing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>2", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "The process that leads to the exchange of value between two or more parties is", "images": [], "options": {"A": "transaction", "B": "production", "C": "distribution", "D": "transportation"}, "answer": "A", "explanation": "A transaction is a process that leads to the exchange of value between two or more parties. It is the act of conducting business or communication between two or more parties with the intention of exchanging goods or services. Therefore, the option 'transaction' is the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>3", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "A short-term incentive used to encourage the purchase of a product is", "images": [], "options": {"A": "advertising", "B": "personal selling", "C": "sales promotion", "D": "publicity"}, "answer": "C", "explanation": "A short-term incentive used to encourage the purchase of a product is a sales promotion. Sales promotions are temporary tactics designed to stimulate either earlier or stronger sales of a product. This can include discounts, coupons, or special offers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>4", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : MEANING OF MARKETING MIX", "question": "The tools used by marketers to pursue their objectives in the target market is marketing", "images": [], "options": {"A": "audit", "B": "mix", "C": "research", "D": "intelligence"}, "answer": "B", "explanation": "The tools used by marketers to pursue their objectives in the target market is the marketing mix. The marketing mix is a business tool used in marketing and by marketers. It is often crucial when determining a product or brand's offer, and is often associated with the four P's: price, product, promotion, and place.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>5", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "PRODUCTS : MEANING", "question": "Activities or benefits offered for sale are", "images": [], "options": {"A": "brands", "B": "values", "C": "goods", "D": "services"}, "answer": "D", "explanation": "Activities or benefits offered for sale are services. In the context of marketing, a service is a type of economic activity that is intangible, is not stored and does not result in ownership. A service is consumed at the point of sale.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>6", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "WAREHOUSING : MEANING, TYPES AND DEFINITIONS", "question": "A warehouse owned and operated by a company for its own use is a", "images": [], "options": {"A": "public warehouse", "B": "private warehouse", "C": "bonded warehouse", "D": "co-operative warehouse"}, "answer": "B", "explanation": "A private warehouse is a storage facility that is owned by the same firm that owns the goods being stored in the facility. The firm has complete control over the operations of the warehouse. This is different from a public warehouse which is a rented space, a bonded warehouse which is a secured area where goods are stored without payment of duty and a co-operative warehouse which is owned and operated by a cooperative society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>7", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "The concept that influence the manufacturing of a low-smoke emission vehicle is", "images": [], "options": {"A": "production concept", "B": "product concept", "C": "selling concept", "D": "societal marketing concept"}, "answer": "D", "explanation": "The societal marketing concept holds that a company should make good marketing decisions by considering consumers' wants, the company's requirements, and society's long-term interests. It is closely linked with the principles of corporate social responsibility and of sustainable development. In this case, manufacturing a low-smoke emission vehicle is a reflection of societal marketing concept as it takes into consideration the society's long-term interest in reducing air pollution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>8", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : MARKETING ENVIRONMENT", "question": "The aggregate of all conditions and events that affects marketing practise is marketing", "images": [], "options": {"A": "procedure", "B": "process", "C": "environment", "D": "communication"}, "answer": "C", "explanation": "The marketing environment refers to the factors and forces that affect a firm's ability to build and maintain successful relationships with customers. It includes the internal environment (employees, customers, shareholders, retailers & distributors, etc.), the micro-environment (competitors, media, publics) and the macro-environment (political, legal, social, economic, technological, environmental, legal forces). The other options such as procedure, process and communication do not fully capture this broad range of factors and forces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>9", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : INFLUECING FACTORS", "question": "A celebrity who influence the buying decision of consumers is categorized under", "images": [], "options": {"A": "social group", "B": "reference group", "C": "peer group", "D": "cultural group"}, "answer": "B", "explanation": "A celebrity who influences the buying decision of consumers is categorized under a 'reference group'. A reference group is a group to which an individual or another group is compared. Celebrities often serve as a reference group influencing consumers' purchase decisions because people tend to compare themselves with celebrities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>10", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : MEANING OF ENTREPRENEURSHIP", "question": "A person who owns and bears the risks of a business is an", "images": [], "options": {"A": "agent", "B": "entrepreneur", "C": "underwriter", "D": "innovator"}, "answer": "B", "explanation": "A person who owns and bears the risks of a business is an 'entrepreneur'. An entrepreneur is an individual who creates a new business, bearing most of the risks and enjoying most of the rewards. The entrepreneur is commonly seen as an innovator, a source of new ideas, goods, services, and business/or procedures.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>11", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : FACTORS AFFECTING MARKETING ENVIRONMENT", "question": "A shift in the consumption pattern of consumers due to a change in interest rate is categorized under", "images": [], "options": {"A": "technological environment factors", "B": "cultural environmental factors", "C": "economic environment factors", "D": "legal environment factors"}, "answer": "C", "explanation": "A shift in the consumption pattern of consumers due to a change in interest rate is categorized under 'economic environment factors'. Economic environment factors include all economic factors that affect consumer buying habits, and spending patterns such as inflation, recession, or an increase in the interest rates.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>12", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : MARKET UNIONS MEANING AND TYPES", "question": "Kano Spare Parts Dealers Association is an example of", "images": [], "options": {"A": "market union", "B": "cartel", "C": "labour union", "D": "chamber of commerce"}, "answer": "A", "explanation": "Kano Spare Parts Dealers Association is an example of a market union. A market union is a group of traders who come together to protect their interests and ensure fair trade practices. They are usually formed by traders dealing in similar goods or services. In this case, the Kano Spare Parts Dealers Association is formed by traders dealing in spare parts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>13", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "PRODUCTS : DISTINCTION BETWEEN CLASSES OF PRODUCTS", "question": "An example of unsought goods is", "images": [], "options": {"A": "Shoe", "B": "Car", "C": "Fire extinguisher", "D": "Machine tool"}, "answer": "C", "explanation": "Unsought goods are goods that the consumer does not know about or does not normally think of buying, and the purchase of which arises due to danger or the fear of danger and lack of desire. The fire extinguisher is a perfect example of an unsought good because it is not a product that consumers think of buying until they need it for safety reasons.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>14", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "SALES PROMOTION : FORMS", "question": "Trade-in-allowance is an example of", "images": [], "options": {"A": "personal allowance", "B": "direct allowance", "C": "dealer sales promotion", "D": "consumer sales promotion"}, "answer": "C", "explanation": "Trade-in-allowance is an example of dealer sales promotion. Dealer sales promotion is a promotional incentive directed at the retailer, wholesaler, or distributor of a product, rather than at the customer. In this case, a trade-in allowance is a discount given for something in return - for example, giving a discount on a new car if the old one is traded in.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>15", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "The banning of tabacco advertisement in Nigeria is an influence from the", "images": [], "options": {"A": "political environment", "B": "economic environment", "C": "social environment", "D": "technological environment"}, "answer": "A", "explanation": "The banning of tobacco advertisement in Nigeria is an influence from the political environment. The political environment refers to the influence of government policy and its administrative practices that can have an effect on something. In this case, the government policy to ban tobacco advertisement is a political influence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>16", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "PRODUCTS : DISTINCTION BETWEEN CLASSES OF PRODUCTS", "question": "The furniture purchased by a company for office use is an example of", "images": [], "options": {"A": "convenience product", "B": "consumer product", "C": "shopping product", "D": "specialty product"}, "answer": "D", "explanation": "The furniture purchased by a company for office use is an example of a specialty product. Specialty products are those that are unique and for specific use. In this case, the furniture is specifically for office use, hence it is a specialty product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>17", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "The systematic design, collection, analysis and reporting of data for decision making is marketing", "images": [], "options": {"A": "planning", "B": "strategy", "C": "audit", "D": "research"}, "answer": "D", "explanation": "The systematic design, collection, analysis, and reporting of data for decision making is marketing research. Marketing research is the process of determining the viability of a new service or product through research conducted directly with potential customers. It allows a company to discover the target market and get opinions and other feedback from consumers about their interest in the product or service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>18", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "Which of the following distribution channel is suitable for the sale of comestics?", "images": [], "options": {"A": "Producer − Consumer", "B": "Producer − Wholesaler − Consumer", "C": "Producer − Wholesaler − Retailer − Consumer", "D": "Producer − Agent − Consumer"}, "answer": "C", "explanation": "The sale of cosmetics typically involves a longer distribution channel because these products are often not sold directly from the producer to the consumer. Instead, they are sold through wholesalers and retailers. Wholesalers buy the products in bulk from the producer and sell them to retailers, who then sell them to the end consumers. This is why the 'Producer − Wholesaler − Retailer − Consumer' channel is most suitable for the sale of cosmetics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>19", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "ADVERTISING : DEFINITION", "question": "The form of non-personal communication whereby information about a company's product is transmitted and paid for through mass media is", "images": [], "options": {"A": "personal selling", "B": "marketing", "C": "public relations", "D": "advertising"}, "answer": "D", "explanation": "Advertising is a form of non-personal communication where information about a company's product is transmitted and paid for through mass media. This can include television, radio, print media, and digital platforms. It is non-personal because it is not directed at a specific individual but rather a large audience. The company pays for this communication, which differentiates it from public relations, where the company does not directly pay for the media coverage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>20", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : INFORMATION REQUIRED FOR MARKETING PLANNING", "question": "An activity in marketing research process is", "images": [], "options": {"A": "decision making", "B": "market testing", "C": "information gathering", "D": "product testing"}, "answer": "C", "explanation": "Information gathering is a crucial activity in the marketing research process. It involves collecting data about the market, the consumers, and the competition. This data is then analyzed to make informed marketing decisions. The other options, such as decision making, market testing, and product testing, are also part of the marketing process but they are not part of the research process per se.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>21", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "PRICING : STRATEGIES", "question": "The pricing strategy which involves the addition of a margin to the total amount spent on production by a company is", "images": [], "options": {"A": "psychological pricing", "B": "cost-plus pricing", "C": "competitive pricing", "D": "geographical pricing"}, "answer": "B", "explanation": "Cost-plus pricing is a pricing strategy that involves the addition of a margin (or markup) to the total cost of a product for profit. This total cost includes the cost of production, labor, and all other expenses incurred in the manufacturing process. The markup is a percentage of the total cost and it represents the profit the company aims to make.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>22", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : INFORMATION REQUIRED FOR MARKETING PLANNING", "question": "The orginal data collected for a study on consumer tastes and fashion by a company is", "images": [], "options": {"A": "a behavioural data", "B": "an organizational data", "C": "a secondary data", "D": "a primary data"}, "answer": "D", "explanation": "Primary data is the original data collected for a specific purpose by or for an organization. In this case, the data on consumer tastes and fashion collected by the company is primary data because it is original and collected for the specific study mentioned in the question.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>23", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "PRICING : PRICE DETERMINANTS", "question": "Which of these factors is not a price determinant?", "images": [], "options": {"A": "Level of market demand", "B": "Economic trend", "C": "Standard of living", "D": "Competitor's price"}, "answer": "C", "explanation": "The standard of living is not a direct determinant of price. Price determinants are factors that affect the price of a product or service. These include the level of market demand, economic trends, and competitor's prices. The standard of living, however, is a socio-economic factor that can influence consumer behavior and market demand, but it does not directly determine the price of a product or service.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>24", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "ICT IN MARKETING : USES, ETHICS AND ABUSES", "question": "Which of the following e-marketing abuses involves an unauthorized use of somebody's identity to extract information?", "images": [], "options": {"A": "Hacking", "B": "Spam", "C": "Phishing", "D": "Cyber fraud"}, "answer": "C", "explanation": "Phishing is a type of cyber attack that involves tricking the email recipient into believing that the message is something they want or need and clicking a link or downloading an attachment. The attacker can steal sensitive data like credit card numbers and login information. It's called phishing because the attacker 'fishes' for the information they want.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>25", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "TRANSPORTATION : DOCUMENTS USED IN TRANSPORTATION", "question": "A document used in domestic transportation is", "images": [], "options": {"A": "manifest", "B": "receipt", "C": "export invoice", "D": "consular invoice"}, "answer": "A", "explanation": "A manifest is a document used in transport that lists the cargo, passengers, and crew of a ship, aircraft, or vehicle for the use of customs and other officials. In the context of domestic transportation, it is used to record the items being transported.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>26", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "PRICING : STRATEGIES", "question": "A type of pricing where a buyer and a seller continue to bargain until an agreement is reached for the price of a product is", "images": [], "options": {"A": "cost-plus", "B": "haggling", "C": "hedging", "D": "loss tender"}, "answer": "B", "explanation": "Haggling is a type of pricing where a buyer and a seller continue to bargain until an agreement is reached for the price of a product. It involves negotiation of the price between the buyer and the seller.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>27", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "TRANSPORTATION : FACTORS AFFECTING CHOICE OF TRANSPORTATION", "question": "An advantage of road transportation over air transportation is that", "images": [], "options": {"A": "fares are not fixed but negotiable", "B": "it is suitable for carrying bulky goods", "C": "movements are on special routes", "D": "it is a faster means of moving goods"}, "answer": "B", "explanation": "Road transportation is more suitable for carrying bulky goods compared to air transportation. This is because road vehicles such as trucks and trailers can carry large and heavy goods, while air transportation has strict weight and size limitations due to the constraints of aircraft design and fuel efficiency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>28", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "Which of these means of advertising is an electronic medium?", "images": [], "options": {"A": "Catalogue", "B": "Television", "C": "Magazine", "D": "Newspaper"}, "answer": "B", "explanation": "Television is an electronic medium used for advertising. It uses both visual and audio signals to transmit information, unlike print media such as catalogues, magazines, and newspapers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>29", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "WAREHOUSING : MEANING, TYPES AND DEFINITIONS", "question": "A facility that would be used by a producer that wants to reduce fluctuations in product supply is", "images": [], "options": {"A": "wholesaling", "B": "retailing", "C": "warehousing", "D": "merchandizing"}, "answer": "C", "explanation": "Warehousing is a facility used by producers to store goods, thereby reducing fluctuations in product supply. It allows for the storage of goods until they are needed in the market, ensuring a steady supply of products. Wholesaling, retailing, and merchandizing are not facilities, but rather stages in the distribution process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>30", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "INTERNATIONAL MARKETING : MEANING, IMPORTANCES AND REASONS", "question": "The application of marketing activities beyond a country's national; boundaries is", "images": [], "options": {"A": "domestic marketing", "B": "wholesale marketing", "C": "retail marketing", "D": "international marketing"}, "answer": "D", "explanation": "The application of marketing activities beyond a country's national boundaries is referred to as international marketing. This involves the company in making one or more marketing mix decisions across national boundaries. It involves the firm in establishing manufacturing facilities overseas and coordinating marketing strategies across the globe.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>31", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "MARKETS : MEANING", "question": "The platform where buyers and sellers are brought together to assist in the transfer of goods and services is", "images": [], "options": {"A": "transportation", "B": "advertising", "C": "distribution", "D": "market"}, "answer": "D", "explanation": "A market is a platform where buyers and sellers are brought together to assist in the transfer of goods and services. It is a place where the forces of demand and supply operate, and where buyers and sellers interact to trade goods, services, or contracts or instruments, for money or barter.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>32", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "INTERNATIONAL MARKETING : GUIDING RULES AND REGULATIONS", "question": "An arrangement whereby a company's name and trademark is used by a foriegn company is", "images": [], "options": {"A": "licensing", "B": "franchising", "C": "joint venture", "D": "strategic alliance"}, "answer": "B", "explanation": "Franchising is an arrangement whereby a company's name and trademark is used by a foreign company. It is a method of distributing products or services involving a franchisor, who establishes the brand's trademark or trade name and a business system, and a franchisee, who pays a royalty and often an initial fee for the right to do business under the franchisor's name and system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>33", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "PRODUCTS : MEANING", "question": "Branding in marketing means", "images": [], "options": {"A": "packing a product for sale", "B": "giving unique name to a product", "C": "using another company's name", "D": "classifying products into groups"}, "answer": "B", "explanation": "Branding in marketing refers to the practice of giving a unique name, symbol or design to a product or service to distinguish it from others in the market. It helps in creating a unique identity and value for a product in the consumers' mind.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>34", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : FACTORS AFFECTING LOCATION OF A MARKET OUTLET", "question": "Which of the following factors is not considered while locating a market outlet?", "images": [], "options": {"A": "Availabilty of Facilities", "B": "Economic trends", "C": "Capital availability", "D": "Source of Supply"}, "answer": "B", "explanation": "While locating a market outlet, factors such as availability of facilities, capital availability, and source of supply are considered. Economic trends, on the other hand, are more relevant to strategic planning and forecasting rather than the physical location of a market outlet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>35", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "MERCHANDISING : MEANING", "question": "The activity that is involved in making products visible,accessible and attractive to consumers in a retail outlet is", "images": [], "options": {"A": "personal selling", "B": "prospecting", "C": "direct selling", "D": "merchandizing"}, "answer": "D", "explanation": "Merchandising refers to the activities involved in displaying products in a retail outlet in a way that is attractive to customers. It includes strategies to increase product visibility, accessibility, and attractiveness to consumers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>36", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : MEANING", "question": "An individual who buys goods for personal consumption is an example of", "images": [], "options": {"A": "organizational market", "B": "industrial market", "C": "consumer market", "D": "reseller market"}, "answer": "C", "explanation": "An individual who buys goods for personal consumption is an example of a consumer market. A consumer market consists of individuals or households who purchase goods for personal consumption and not for resale or business purposes. The other options such as organizational market, industrial market, and reseller market refer to markets where goods are purchased for business purposes or for resale.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>37", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "ICT IN MARKETING : E-MARKETING - MEANING, IMPORTANCE", "question": "A reason why e-marketing is important is that it", "images": [], "options": {"A": "provides avenue for immediate inspection of products", "B": "offers unsolicted mesages to customers", "C": "demonstrates practical use of products", "D": "offers unlimited access to customers"}, "answer": "D", "explanation": "E-marketing is important because it offers unlimited access to customers. With the internet, businesses can reach out to customers from all over the world at any time. This is not possible with traditional marketing methods. The other options such as providing avenue for immediate inspection of products, offering unsolicited messages to customers, and demonstrating practical use of products are not the primary reasons why e-marketing is important.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>38", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "Which of these steps is followed in the process of buying by an individual?    I. Information search  II. Problem recognition  III. Evaluation of alternatives  IV. Purchase decision  V. Post purchase behaviour", "images": [], "options": {"A": "V,IV,III,II,I", "B": "III,IV,II,I,IV", "C": "II,I,III,IV,V", "D": "I,II,III,IV,V"}, "answer": "C", "explanation": "The process of buying by an individual typically follows these steps: Problem recognition, Information search, Evaluation of alternatives, Purchase decision, and Post purchase behaviour. This is represented by the option II,I,III,IV,V. The other options do not correctly represent the sequence of steps in the buying process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2020>39", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "The channel member that sells in small quantities to consumer is", "images": [], "options": {"A": "an agent", "B": "a broker", "C": "a retailer", "D": "a wholesaler"}, "answer": "C", "explanation": "A retailer is a channel member that sells products in small quantities to consumers. They are the final link in the distribution chain that connects manufacturers to consumers. Agents, brokers, and wholesalers typically deal with bulk quantities and sell to other businesses rather than directly to consumers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2020>40", "subject": "Marketing", "year": "2020", "type": "Objective", "topic": "DISTRIBUTION : DEFINITION", "question": "The route through which products flows from the producer to the ultimate consumer is", "images": [], "options": {"A": "marketing intermediary", "B": "distribution channel", "C": "merchandizing", "D": "transportation"}, "answer": "B", "explanation": "The route through which products flow from the producer to the ultimate consumer is known as the distribution channel. This can include manufacturers, wholesalers, distributors, and retailers. Marketing intermediaries are part of the distribution channel, but they do not represent the entire route. Merchandising and transportation are aspects of the distribution process, but they do not represent the entire route either.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>1", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "A short -term tool used in boosting turnover is", "images": [], "options": {"A": "sales promotion", "B": "mass media", "C": "personal selling", "D": "e-marketing"}, "answer": "A", "explanation": "Sales promotion is a short-term marketing strategy designed to stimulate quicker and greater purchase of particular products or services by consumers. It often involves temporary incentives to encourage purchases. Mass media, personal selling, and e-marketing are all marketing tools, but they are not specifically designed for short-term sales boosts.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>2", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "ADVERTISING : PRODUCTION OF SAMLE ADVERTS", "question": "The part of an advertising leaflet that introduces the message of the advertisement is", "images": [], "options": {"A": "margin", "B": "headline", "C": "cut-out", "D": "photograph"}, "answer": "B", "explanation": "The headline of an advertising leaflet is the part that introduces the message of the advertisement. It is designed to catch the reader's attention and give them an idea of what the advertisement is about.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>3", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "PRICING : MEANING", "question": "The amount of money charged for a product is the", "images": [], "options": {"A": "fare", "B": "price", "C": "revenue", "D": "cash"}, "answer": "B", "explanation": "The amount of money charged for a product is referred to as the price. This is the monetary value that a seller sets for a product, which the buyer must pay to purchase the product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>4", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "Am advertising media with the highest coverage area is", "images": [], "options": {"A": "Billboard", "B": "catalogue", "C": "magazine", "D": "television"}, "answer": "D", "explanation": "Television is the advertising media with the highest coverage area. It has the ability to reach a wider audience compared to other forms of advertising media such as billboards, catalogues, and magazines. This is because television broadcasts can be received by households across a country or even internationally.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>5", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "PRICING : STRATEGIES", "question": "A pricing strategy in which the buyer and seller bargain to reach an agreement on the price of a product is", "images": [], "options": {"A": "cost-plus", "B": "haggling", "C": "skimming pricing", "D": "penetration pricing"}, "answer": "B", "explanation": "Haggling is a pricing strategy where the buyer and seller negotiate to reach an agreement on the price of a product. It is a common practice in many markets, especially in traditional markets where prices are not fixed. The other options do not involve negotiation between buyer and seller. Cost-plus pricing is a strategy where the selling price is determined by adding a specific amount markup to a product's unit cost. Skimming pricing is a strategy where a high price is set for a new product to skim maximum revenues layer by layer from those willing to pay the high price. Penetration pricing is a strategy where a product is priced low to stimulate product awareness and trial.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>6", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "The elements that make up marketing planning are   I. situation analysis   II. market share   III. marketing objective   IV. marketing strategy   V. action programme", "images": [], "options": {"A": "I,II,III,IV only", "B": "I,II,III,V only", "C": "I,II,IV,V only", "D": "I,III,IV,V only"}, "answer": "D", "explanation": "The elements that make up marketing planning are situation analysis, marketing objective, marketing strategy, and action programme. Situation analysis involves evaluating the current state of the market and the company's position within it. Marketing objective sets out what a business wants to achieve from its marketing activities. Marketing strategy is the overall game plan of a business for reaching prospective consumers and turning them into customers. Action programme is the detailed plan of activities or tactics to be used to achieve the marketing objectives. Market share is not an element of marketing planning, it is a result or outcome of effective marketing planning.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>7", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : REASONS FOR MARKETING PLANNING AND RESEARCH", "question": "The process of collecting and analyzing information about the external marketing environment is", "images": [], "options": {"A": "environmental management", "B": "marketing research", "C": "market segmentation", "D": "marketing management"}, "answer": "B", "explanation": "The process of collecting and analyzing information about the external marketing environment is known as marketing research. It involves gathering data about consumers, competitors, and market trends to aid in decision making. Environmental management is the practice of managing and controlling the impact of business activities on the environment. Market segmentation is the process of dividing a market into distinct groups of buyers with different needs, characteristics, or behaviors. Marketing management is the process of planning, organizing, directing, and controlling the resources of the marketing department in an organization to achieve the desired marketing objectives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>8", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : INFLUECING FACTORS", "question": "Which of the following behaviours would a satisfied customer exhibit?", "images": [], "options": {"A": "Buy similar products from other companies", "B": "Pay attention to other companies' product advertisement", "C": "Talk favourably about the purchased products", "D": "Recommend competing products for buying"}, "answer": "C", "explanation": "A satisfied customer is likely to talk favourably about the purchased products. This is because they have had a positive experience with the product and are likely to share this with others. This is a form of word-of-mouth marketing, which is very effective as it is based on the personal experiences and opinions of customers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>9", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : MEANING", "question": "Which of the following is not an example of institutional consumers?", "images": [], "options": {"A": "Schools", "B": "Hospitals", "C": "Hotels", "D": "Households"}, "answer": "D", "explanation": "Institutional consumers are organizations that buy goods and services for use in their operations. Examples include schools, hospitals, and hotels. Households, on the other hand, are considered individual or personal consumers, not institutional consumers, because they purchase goods and services for personal use.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>10", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "SALES PROMOTION : FORMS", "question": "Which of the following sales promotional tool is used to encourage wholesalers and retailers?", "images": [], "options": {"A": "Sample pack", "B": "Bonus pack", "C": "Premium offer", "D": "Price discount"}, "answer": "D", "explanation": "Price discount is a sales promotional tool used to encourage wholesalers and retailers. This is because a price discount allows wholesalers and retailers to purchase the product at a lower cost, increasing their potential profit margin when they sell the product to the end consumer. This makes the product more attractive to wholesalers and retailers, encouraging them to stock and sell the product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>11", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "Which of the following consumer buying behaviours requires the least efforts?", "images": [], "options": {"A": "Impulse buying", "B": "Routine buying", "C": "New buying", "D": "High buying"}, "answer": "B", "explanation": "Routine buying requires the least effort because it involves purchasing items that are regularly needed and for which a purchase decision has already been made. Impulse buying, new buying, and high buying all require more effort because they involve making a decision at the point of purchase, researching and deciding on a new product, and spending a large amount of money, respectively.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>12", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "PRODUCTS : CLASSIFICATION", "question": "An example of non- durable goods is", "images": [], "options": {"A": "shoe", "B": "bread", "C": "television", "D": "refridgerator"}, "answer": "B", "explanation": "Non-durable goods, also known as consumable goods, are products that are consumed over a short period of time. Bread is a non-durable good because it is consumed shortly after purchase and has a short lifespan. Shoes, televisions, and refrigerators are all durable goods because they are used over a longer period of time.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>13", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "ICT IN MARKETING : E-MARKETING - MEANING, IMPORTANCE", "question": "E-marketing is also called", "images": [], "options": {"A": "direct purchasing", "B": "electronic banking", "C": "e-mail order", "D": "internet business"}, "answer": "D", "explanation": "E-marketing is also known as internet business. It involves the use of the internet to market and sell goods and services. Direct purchasing, electronic banking, and e-mail order are all components of e-marketing, but they do not define the entire concept.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>14", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "PRODUCTS : PRODUCT DESIGN", "question": "A product that has undergone processing is", "images": [], "options": {"A": "an intangible product", "B": "a primary product", "C": "an extractive product", "D": "a secondary product"}, "answer": "D", "explanation": "A product that has undergone processing is a secondary product. A secondary product is a type of product that has been manufactured from raw materials. It involves the conversion of raw material into finished goods. So, any product that has undergone processing falls under this category.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>15", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "PRODUCTS : CLASSIFICATION", "question": "Which of the following items is a primary product?", "images": [], "options": {"A": "Sugar", "B": "Noodles", "C": "Fresh tomatoes", "D": "Fresh bread"}, "answer": "C", "explanation": "A primary product is a product in its natural state, i.e., it has not undergone any processing or manufacturing. Fresh tomatoes are a primary product because they are harvested directly from the farm and have not undergone any form of processing or manufacturing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>16", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "The formation of a strategy to attain established marketing objectives is", "images": [], "options": {"A": "marketing concept", "B": "marketing forecast", "C": "market demand", "D": "market planning"}, "answer": "D", "explanation": "The formation of a strategy to attain established marketing objectives is known as market planning. Market planning involves identifying and documenting a plan of action to achieve marketing goals. It includes the strategies, tactics, and resources necessary to achieve these objectives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>17", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : FACTORS AFFECTING MARKETING ENVIRONMENT", "question": "A reduction in general personal income which leads to a change in a company's pricing strategy is an element of the", "images": [], "options": {"A": "competitive environment", "B": "political environment", "C": "economic environment", "D": "technological environment"}, "answer": "C", "explanation": "A reduction in general personal income which leads to a change in a company's pricing strategy is an element of the economic environment. The economic environment refers to all the economic factors that affect consumer buying habits in a market. These factors include income levels, inflation rates, employment levels, and economic policies. When personal income reduces, consumers have less disposable income to spend, which may force companies to adjust their pricing strategies to maintain sales.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>18", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL MARKETING : MEANING, IMPORTANCES AND REASONS", "question": "Marketing activities carried out in more than one country is", "images": [], "options": {"A": "international marketing", "B": "national marketing", "C": "home trade", "D": "entreport trade"}, "answer": "A", "explanation": "Marketing activities carried out in more than one country is referred to as international marketing. International marketing involves the company in making one or more marketing mix decisions across national boundaries. It involves the firm in establishing manufacturing facilities overseas and coordinating marketing strategies across the globe.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>19", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : MARKET FACILITATORS - MEANING, TYPES AND ROLES", "question": "Individuals or firms that enhance business activities but do not participate directly in the business are", "images": [], "options": {"A": "market unions", "B": "market facilitators", "C": "wholesalers", "D": "retailers"}, "answer": "B", "explanation": "Individuals or firms that enhance business activities but do not participate directly in the business are known as market facilitators. Market facilitators are entities or individuals who help a business to function more efficiently but do not have a direct stake in the outcome of the business. They provide necessary services to ensure the smooth operation of the market, such as logistics, financial services, or marketing research.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>20", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : MARKET UNIONS MEANING AND TYPES", "question": "The body formed by sellers of a common product in a local market is an example of", "images": [], "options": {"A": "market union", "B": "manufacturers' association", "C": "trade union", "D": "consumers' association"}, "answer": "A", "explanation": "A market union is a group of sellers who sell a common product in a local market. They come together to form a union to protect their interests and to have a collective bargaining power. A manufacturers' association is a group of manufacturers who come together to protect their interests, but they may not necessarily sell in a local market. A trade union is a group of workers who come together to protect their interests. A consumers' association is a group of consumers who come together to protect their interests.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>21", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "TRANSPORTATION : MEANING,MODE, CHOICE AND IMPORTANCE", "question": "The cheapest mode of transporting imported cars from America to Nigeria is by", "images": [], "options": {"A": "air", "B": "road", "C": "water", "D": "rail"}, "answer": "C", "explanation": "The cheapest mode of transporting imported cars from America to Nigeria is by water. This is because water transport is cheaper than air, road, and rail transport for long-distance and international transportation. Air transport is the most expensive mode of transport. Road and rail transport may not be feasible for international transportation between America and Nigeria due to geographical barriers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>22", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "The middlemen that buys in bulk and sells in bit is", "images": [], "options": {"A": "a retailer", "B": "an agent", "C": "a wholesaler", "D": "a broker"}, "answer": "C", "explanation": "A wholesaler is a middleman that buys in bulk and sells in bit. They buy goods in large quantities from manufacturers and sell them in smaller quantities to retailers. A retailer is a middleman that buys from wholesalers and sells directly to consumers. An agent is a middleman that acts on behalf of a manufacturer or a wholesaler to sell their goods. A broker is a middleman that brings a buyer and a seller together and facilitates a transaction between them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>23", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "Which of the following channels of distribution would a producer who wants to control its unit price use?", "images": [], "options": {"A": "Producer ------≻ Consumer", "B": "Producer ------≻ Retailer------≻Consumer", "C": "Producer------≻Wholesaler------≻Retailer------≻Consumer", "D": "Producer------≻Agent------≻Retailer------≻Consumer"}, "answer": "A", "explanation": "A producer who wants to control its unit price would use the direct channel of distribution, which is from the producer directly to the consumer. This is because the producer has full control over the pricing and does not have to share profits with intermediaries such as wholesalers, retailers, or agents.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>24", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "TRANSPORTATION : DOCUMENTS USED IN TRANSPORTATION", "question": "An example of transportation document that is used for local trade is", "images": [], "options": {"A": "waybill", "B": "certificate of origin", "C": "consular invoice", "D": "bill of lading"}, "answer": "A", "explanation": "A waybill is a document issued by a carrier giving details and instructions relating to the shipment of a consignment of goods. Typically it will show the names of the consignor and consignee, the point of origin of the consignment, its destination, and route. It is used for local trade.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>25", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : MEANING", "question": "All individuals and units that buy goods for personal use can constitute the", "images": [], "options": {"A": "industrial market", "B": "consumer market", "C": "government market", "D": "re-seller market"}, "answer": "B", "explanation": "The consumer market consists of individuals and households who buy goods for their own personal use. The industrial market consists of businesses that buy goods for use in their operations. The government market consists of government agencies that buy goods to carry out public projects. The re-seller market consists of intermediaries who buy goods to resell at a profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>26", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MERCHANDISING : FUNCTIONS", "question": "Which of the following activities is not a function of a merchandiser?", "images": [], "options": {"A": "Displaying products in the best location", "B": "Identifying potential new accounts", "C": "Maintaining and increasing shelf space", "D": "Cleaning and displaying of products"}, "answer": "B", "explanation": "A merchandiser's role is primarily concerned with promoting products in a retail setting. This includes tasks such as displaying products in the best location, maintaining and increasing shelf space, and cleaning and displaying of products. Identifying potential new accounts is typically a function of sales or business development, not merchandising.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>27", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "PRODUCTS : PRODUCT DESIGN", "question": "The differentiation of a firm's product from other competing goods is", "images": [], "options": {"A": "packaging", "B": "labelling", "C": "coding", "D": "branding"}, "answer": "D", "explanation": "Branding is the process of differentiating a company's products from its competitors. This is achieved by creating a unique name, symbol, or design that identifies and differentiates a product. While packaging, labelling, and coding can contribute to this differentiation, they are components of the overall branding strategy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>28", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "WAREHOUSING : MEANING, TYPES AND DEFINITIONS", "question": "A disadvantage of warehousing is that it", "images": [], "options": {"A": "encourages hoarding of goods to create scarcity", "B": "ensures the availability of goods when needed", "C": "helps to protect goods from damages", "D": "ensure availiability of storage facility for goods"}, "answer": "A", "explanation": "Warehousing, or the storage of goods, can potentially encourage hoarding of goods to create scarcity. This is because when goods are stored in large quantities, it can create an artificial scarcity in the market, which can lead to price manipulation. The other options listed are generally considered advantages of warehousing, as they ensure the availability and protection of goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>29", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : MARKETING ENVIRONMENT", "question": "An element of the external marketing environment is", "images": [], "options": {"A": "organizational policy", "B": "company procedures", "C": "corporate culture", "D": "economic indices"}, "answer": "D", "explanation": "The external marketing environment refers to factors and forces outside the organization that affect its marketing operations. These include economic, social, political, technological, and competitive factors. Economic indices are part of the external marketing environment as they reflect the economic conditions that can affect consumer buying power and spending patterns.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>30", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : MEANING OF MARKETING MIX", "question": "An element of the marketing mix is", "images": [], "options": {"A": "processes", "B": "place", "C": "packaging", "D": "production"}, "answer": "B", "explanation": "The marketing mix, also known as the 4Ps of marketing, includes Product, Price, Place, and Promotion. 'Place' refers to the distribution channels used to get the product to the customers. It involves the location where the products are sold and any distribution channels used.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>31", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "WAREHOUSING : MEANING, TYPES AND DEFINITIONS", "question": "Which of the following options is not a function of a warehouse?", "images": [], "options": {"A": "To increase the price of goods", "B": "Store goods for consumption purpose", "C": "Store goods till when needed for supply", "D": "Stabilization of price of goods"}, "answer": "A", "explanation": "The functions of a warehouse include storage of goods, price stabilization, risk bearing, financing, and grading and packing. However, increasing the price of goods is not a function of a warehouse. Warehouses are used to store goods until they are needed, not to increase their prices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>32", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : MEANING OF ENTREPRENEURSHIP", "question": "The willingness and ability to identify business opportunity, establish and operate it successfully is", "images": [], "options": {"A": "distribution", "B": "wholesaling", "C": "entreprenuership", "D": "purchasing"}, "answer": "C", "explanation": "The willingness and ability to identify business opportunity, establish and operate it successfully is referred to as entrepreneurship. Entrepreneurs are individuals who, rather than working as an employee, found and run a small business, assuming all the risks and rewards of the venture.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>33", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : SOURCES OF FUNDS", "question": "An internal source of fund for an entreprenuer is", "images": [], "options": {"A": "bank loan", "B": "overdraft", "C": "trade credit", "D": "retained earnings"}, "answer": "D", "explanation": "An internal source of fund for an entrepreneur is retained earnings. Retained earnings are the portion of a company's profit that is held or retained and saved for future use. Retained earnings could be used for funding an expansion or paying dividends to shareholders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>34", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : SOURCES OF FUNDS", "question": "An example of long-term source of fund for an entrepreneur is", "images": [], "options": {"A": "debenture", "B": "trade credits", "C": "overdraft", "D": "customers advances"}, "answer": "A", "explanation": "An example of long-term source of fund for an entrepreneur is debenture. A debenture is a type of debt instrument that is not secured by physical assets or collateral. Debentures are backed only by the general creditworthiness and reputation of the issuer. They are typically issued for a period of more than a year.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>35", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "The idea that consumers will prefer goods and services that are available and afforadable is", "images": [], "options": {"A": "selling concept", "B": "product concept", "C": "production concept", "D": "marketing concept"}, "answer": "C", "explanation": "The production concept is a business notion that consumers prefer products that are widely available and inexpensive. This concept is derived from the approach of mass production and economies of scale where businesses focus on high production output and global distribution in order to achieve cost advantages.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>36", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "Which of the following alternatives is a purpose of marketing concept?", "images": [], "options": {"A": "Product quality", "B": "Consumer satisfaction", "C": "Sales volume", "D": "Production volume"}, "answer": "B", "explanation": "The marketing concept is a business philosophy that emphasizes the importance of satisfying the needs and wants of consumers. It suggests that businesses should strive to meet the needs of their customers while also achieving their own goals. Therefore, consumer satisfaction is a primary purpose of the marketing concept.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>37", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "INTRODUCTION TO MARKETING : FUNCTIONS", "question": "Marketers are involved in production process because", "images": [], "options": {"A": "they also work in the factory floor", "B": "their ideas are developed into products", "C": "they set product price", "D": "they purchase raw materials for production"}, "answer": "B", "explanation": "Marketers are involved in the production process because their ideas are developed into products. They conduct market research to understand consumer needs and preferences, and these insights are used to develop products that meet these needs. Therefore, marketers play a crucial role in the product development process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>38", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "PRICING : STRATEGIES", "question": "If the unit cost price of a product is #90 and sold at a profit margin of 50%, what is the selling price?", "images": [], "options": {"A": "#45", "B": "#90", "C": "#135", "D": "#180"}, "answer": "C", "explanation": "The selling price of a product sold at a profit margin of 50% is calculated by adding the profit margin to the cost price. The profit margin is 50% of the cost price, which is #45. Therefore, the selling price is #90 + #45 = #135.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2021>39", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL MARKETING : MEANING, IMPORTANCES AND REASONS", "question": "A company that sells its goods direclty in foreign countries is engaging in", "images": [], "options": {"A": "exportation", "B": "importation", "C": "franchising", "D": "licencing"}, "answer": "A", "explanation": "A company that sells its goods directly in foreign countries is engaging in exportation. Exportation is the act of selling goods or services produced in one country to another country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2021>40", "subject": "Marketing", "year": "2021", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : ROLES OF MARKET UNIONS", "question": "A function of market union in a local market is to", "images": [], "options": {"A": "defend members at law court", "B": "offer bank loan to members", "C": "transport products on behalf of members", "D": "establish common price for their products"}, "answer": "D", "explanation": "A function of market union in a local market is to establish common price for their products. Market unions often set common prices for their products to prevent unfair competition and ensure that all members can sell their products at a reasonable price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>1", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "PRODUCTS : CLASSIFICATION", "question": "Which of the following items is an example of industrial goods?", "images": [], "options": {"A": "Cassava tubber", "B": "Toothpaste", "C": "Bread", "D": "Cake"}, "answer": "A", "explanation": "Industrial goods are goods that need to undergo processing i.e they are raw materials that would be converted into semi-finished or finished goods. Examples: cotton wool, timber, fresh fish, fresh tomatoes etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>2", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "INTRODUCTION TO MARKETING : HISTORY", "question": "The first institution to introduce a degree programme in marketing in Nigeria is University of", "images": [], "options": {"A": "Ibadan", "B": "Nigeria, Nsukka", "C": "Lagos", "D": "Jos"}, "answer": "B", "explanation": "The University of Nigeria, Nsukka was the first institution to introduce a degree programme in marketing in Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>3", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "INTRODUCTION TO MARKETING : BASIC TERMS", "question": "Which of the following marketing terms is applied to a buyer that obtains a desired product by offering something in return?", "images": [], "options": {"A": "Needs", "B": "Wants", "C": "Demand", "D": "Exchange"}, "answer": "D", "explanation": "The term 'Exchange' is applied to a buyer that obtains a desired product by offering something in return. It is a key concept in marketing where two parties give and receive something of value.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>4", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "A company's orientation that concentrates on mass distribution and low cost of its product is a", "images": [], "options": {"A": "product concept", "B": "production concept", "C": "marketing concept", "D": "selling concept"}, "answer": "B", "explanation": "The production concept is a business orientation that focuses on high production efficiency, low costs, and mass distribution. It assumes that customers will favor products that are available and highly affordable, and it focuses on improving production and distribution efficiency.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>5", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "Which of the following business orientations stresses that promotional efforts are necessary before customers buy a product?", "images": [], "options": {"A": "Production concept", "B": "Product concept", "C": "Selling concept", "D": "Marketing concept"}, "answer": "C", "explanation": "The selling concept holds that consumers and businesses, if left alone, will ordinarily not buy enough of the organization's products. The organization must, therefore, undertake an aggressive selling and promotion effort. This concept assumes that consumers typically sho9w buying inertia or resistance and must be coaxed into buying.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>6", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : MEANING OF MARKETING MIX", "question": "A set of controllable variables that a firm uses to pursue its objectives is", "images": [], "options": {"A": "product mix", "B": "product concept", "C": "selling concept", "D": "marketing mix"}, "answer": "D", "explanation": "The marketing mix refers to the set of actions, or tactics, that a company uses to promote its brand or product in the market. The 4Ps make up a typical marketing mix - Price, Product, Promotion and Place. However, nowadays, the marketing mix increasingly includes several other Ps like Packaging, Positioning, People and even Politics as vital mix elements.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>7", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "PRODUCTS : PRODUCT DESIGN", "question": "A feature of product as a marketing mix element is", "images": [], "options": {"A": "credit terms", "B": "warranty", "C": "cash discount", "D": "allowances"}, "answer": "B", "explanation": "A feature of a product as a marketing mix element refers to the characteristics or attributes of the product that make it appealing or beneficial to the consumer. Warranty is a feature of a product that guarantees the product's performance and offers a solution if the product fails to perform as expected. It is a promise made by the manufacturer to the customer that the product will meet certain standards.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>8", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : ELEMENT", "question": "Which marketing mix element is applicable when a firm provides parking space for its customers?", "images": [], "options": {"A": "Process", "B": "People", "C": "Price", "D": "Promotion"}, "answer": "A", "explanation": "The provision of parking space for customers is related to the 'Process' element of the marketing mix. The marketing mix is a set of actions that a company uses to promote its brand or product in the market. The 'Process' element refers to the systems and processes that deliver a product or service to the customer. Providing parking space is part of the process of making the shopping experience convenient and pleasant for the customer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>9", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "PRODUCTS : MEANING", "question": "In marketing, the term product refers to", "images": [], "options": {"A": "any item that can be seen or touched", "B": "anything that can be offered for consumption", "C": "goods and ideas", "D": "packages' design and warranty"}, "answer": "B", "explanation": "In marketing, the term 'product' refers to anything that can be offered to a market for attention, acquisition, use, or consumption that might satisfy a want or need. It includes physical goods, services, experiences, events, persons, places, properties, organizations, information, and ideas. Therefore, the option 'anything that can be offered for consumption' is the most accurate definition.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>10", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "PRODUCTS : CLASSIFICATION", "question": "Milk, sugar and bread bought by Amaka for her chilrens's breakfast are examples of", "images": [], "options": {"A": "shopping goods", "B": "convenience goods", "C": "speciality goods", "D": "unsought goods"}, "answer": "B", "explanation": "Milk, sugar, and bread are examples of convenience goods. Convenience goods are items that are regularly consumed and are readily available for purchase. These are goods that consumers buy frequently, immediately and with minimal comparison and buying effort.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>11", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : MEANING", "question": "Companies that purchase goods for futher processing is an example of", "images": [], "options": {"A": "a consumer market", "B": "an  industrial market", "C": "a reseller market", "D": "a government market"}, "answer": "B", "explanation": "Companies that purchase goods for further processing are examples of an industrial market. An industrial market consists of all businesses that buy goods and services for use in production of other products and services that are sold, rented, or supplied to others.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>12", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : MEANING", "question": "Which of the following statements explains an organizational market?", "images": [], "options": {"A": "Buyers are widespread", "B": "Buyers are price conscious", "C": "Purchasing is on first-come, first- served basis", "D": "Purchasing is done by trained personnel"}, "answer": "D", "explanation": "An organizational market is characterized by the fact that purchasing is done by trained personnel. These are professionals who understand the needs of the organization and are able to make informed decisions about what to purchase, from whom, and at what price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>13", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "At what stage in the buying process does a consumer consider product atttributes of available brands?", "images": [], "options": {"A": "Alternative search", "B": "Alternative evaluation", "C": "Purchase decision", "D": "Post-purchase decision"}, "answer": "B", "explanation": "The consumer considers product attributes of available brands during the 'Alternative evaluation' stage. This is the stage where the consumer uses information to evaluate alternative brands in the choice set. The consumer ranks the alternatives and forms purchase intentions based on the evaluation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>14", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "The last stage in the consumer buying decision process is", "images": [], "options": {"A": "information search", "B": "evaluation of alternatives", "C": "problem recognition", "D": "post-purchase decision"}, "answer": "D", "explanation": "The last stage in the consumer buying decision process is 'Post-purchase decision'. After purchasing the product, the consumer will experience some level of satisfaction or dissatisfaction, and will engage in post-purchase behavior of interest to the marketer. This may involve post-purchase communication, product use and disposal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>15", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "The process of collecting and analyzing relevant information to solve a marketing problem is marketing", "images": [], "options": {"A": "intelligence", "B": "research", "C": "audit", "D": "planning"}, "answer": "B", "explanation": "The process of collecting and analyzing relevant information to solve a marketing problem is referred to as 'Marketing research'. Marketing research involves the identification, collection, analysis and dissemination of information for the purpose of improving decision making related to the identification and solution of problems and opportunities in marketing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>16", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : INFORMATION REQUIRED FOR MARKETING PLANNING", "question": "An information required for marketing planning is", "images": [], "options": {"A": "product quality control mechanism", "B": "company's recruitment policy", "C": "previous year's sales volume", "D": "company's financial policy"}, "answer": "C", "explanation": "Marketing planning involves the strategic planning of a company's marketing activities. This includes understanding the market, setting marketing objectives, and developing marketing strategies. One of the key pieces of information required for this process is the previous year's sales volume. This data helps in understanding the market trends, customer preferences, and the effectiveness of past marketing strategies. It does not directly involve the product quality control mechanism, company's recruitment policy, or the company's financial policy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>17", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : UTILIZATION OF FEEDBACK", "question": "The purpose of feedback from customers who use  a company's product is to", "images": [], "options": {"A": "train marketing staff", "B": "improve the quality of products", "C": "determine distribution channel to adopt", "D": "determine the promotional tool to adopt"}, "answer": "B", "explanation": "Feedback from customers is crucial for any business as it provides insights into what is working well about a product or service and what should be improved. It is a direct line of communication with customers to ensure that their needs and expectations are met. Therefore, the purpose of feedback from customers who use a company's product is to improve the quality of products. It does not directly train marketing staff, determine distribution channel to adopt, or determine the promotional tool to adopt.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>18", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "PRICING : APPLICATION", "question": "Use the following information to answer questions below    A retailer's cost and selling price for a bag of rice are #10,000 and #14,000 respectively.    What is the company's mark-up on cost?", "images": [], "options": {"A": "28.6%", "B": "35%", "C": "40%", "D": "71.4%"}, "answer": "C", "explanation": "Mark up =  Profit/ Cost price  x 100     Profit = 14,000 - 10,000  = 4,000    Mark up = 4,000/ 10,000   x 100     = 40%", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>19", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "PRICING : APPLICATION", "question": "Use the following information to answer questions below    A retailer's cost and selling price for a bag of rice are #10,000 and #14,000 respectively.  What is the retailer's profit per bag of rice if he incurs an addtional cost of #500 on each bag of rice?", "images": [], "options": {"A": "#3,000", "B": "#3,500", "C": "#4,000", "D": "#4,500"}, "answer": "B", "explanation": "The retailer's profit per bag of rice is calculated by subtracting the total cost from the selling price. The total cost is the sum of the cost price and the additional cost, which is #10,000 + #500 = #10,500. Therefore, the profit is #14,000 - #10,500 = #3,500.", "marks": "1", "difficulty": "3"}, {"id": "objective>Marketing>2022>20", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "ADVERTISING : FUNCTIONS", "question": "Which of the following activities is not a function of advertising? It", "images": [], "options": {"A": "informs the audience about a product", "B": "reminds the audience about a product", "C": "is used in place of personal selling", "D": "encourages middlemen to stock a product desired"}, "answer": "C", "explanation": "Advertising is a marketing communication that employs an openly sponsored, non-personal message to promote or sell a product, service or idea. It informs and reminds the audience about a product, and encourages middlemen to stock a product. However, it is not used in place of personal selling. Personal selling involves a direct face-to-face relationship between an organization and its customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>21", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "An example of a non-personal means of reaching the target audience by an identified sponsor is", "images": [], "options": {"A": "personal selling", "B": "coupon", "C": "sales promotion", "D": "billboard"}, "answer": "D", "explanation": "Non-personal means of reaching the target audience by an identified sponsor refers to methods that do not involve direct face-to-face interaction. Among the options, billboard is a non-personal means of communication. Personal selling is a personal method, coupon and sales promotion can be both personal and non-personal but they are not means of communication.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>22", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "PRICING : STRATEGIES", "question": "A reason for granting quantity discount is to", "images": [], "options": {"A": "encourage prompt payment", "B": "encourage bulk purchases", "C": "make sales outlet popular", "D": "encourage competitions"}, "answer": "B", "explanation": "Quantity discounts are reductions in cost that are given to customers when they purchase large quantities of a product. The main reason for granting quantity discounts is to encourage bulk purchases. This is because when customers buy in bulk, it reduces the cost of inventory management and increases sales volume.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>23", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "SALES PROMOTION : FORMS", "question": "Coupon is used as a sales promotional tool targeted at", "images": [], "options": {"A": "wholesalers", "B": "consumers", "C": "retailers", "D": "salemen"}, "answer": "B", "explanation": "A coupon is a sales promotional tool that is primarily targeted at consumers. It offers a discount or rebate when purchasing a product. The main aim of using coupons is to attract new customers, to retain existing customers, or to quickly sell off old inventory. It is not targeted at wholesalers, retailers, or salesmen as they are part of the distribution channel and not the end users of the product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>24", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "MERCHANDISING : MEANING", "question": "The creation of awareness for products at the point of sale is", "images": [], "options": {"A": "sale promotion", "B": "sampling", "C": "personal selling", "D": "merchandising"}, "answer": "D", "explanation": "Merchandising refers to the variety of products available for sale and the display of those products in such a way that it stimulates interest and entices customers to make a purchase. The creation of awareness for products at the point of sale is therefore achieved through merchandising. This can involve display techniques, free samples, on-the-spot demonstration, pricing, shelf talkers, special offers, and other point-of-sale methods.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>25", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "MERCHANDISING : FUNCTIONS", "question": "An example of merchandising activities is", "images": [], "options": {"A": "canvasing for customers by salemen", "B": "displaying products at the retail store", "C": "distributing of goods to customers", "D": "sales call by salesmen"}, "answer": "B", "explanation": "Merchandising activities refer to the various methods used by businesses to promote and sell their products. One of the most common methods is displaying products at the retail store.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>26", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "The channel member who does not take title to goods is the", "images": [], "options": {"A": "retailer", "B": "wholesaler", "C": "agent", "D": "distributor"}, "answer": "C", "explanation": "In a distribution channel, the agent is the one who does not take title to goods. They simply facilitate the sale from the producer to the consumer or retailer without owning the goods.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>27", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "Which of the following distribution channels would be used to sell tractors and cranes?", "images": [], "options": {"A": "Producer----->Agent-----------> Consumer", "B": "Producer----->Agent-----------> Retailer---------------->Consumer", "C": "Producer----->Agent-----------> Wholesaler--------------->Retailer------------------>Consumer", "D": "Producer----->Agent-----------> Wholesaler--------------->Consumer"}, "answer": "A", "explanation": "Tractors and cranes are large, expensive, and specialized equipment that are typically sold directly from the producer to the consumer or through an agent.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>28", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "TRANSPORTATION : DOCUMENTS USED IN TRANSPORTATION", "question": "The document that shows the details of goods being transported is the", "images": [], "options": {"A": "Bill of Exchange", "B": "invoice", "C": "waybill", "D": "Certificate of Origin"}, "answer": "C", "explanation": "A waybill is a document issued by a carrier giving details and instructions relating to the shipment of a consignment of goods. Typically it will show the names of the consignor and consignee, the point of origin of the consignment, its destination, and route.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>29", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "TRANSPORTATION : MEANING,MODE, CHOICE AND IMPORTANCE", "question": "One of the reasons transportation is important is that it", "images": [], "options": {"A": "ensures customers's satisfaction", "B": "ensures profit maximization", "C": "facilitates the distribution of goods", "D": "ensures stabilization of product price"}, "answer": "C", "explanation": "Transportation plays a key role in the distribution of goods, providing the physical means by which goods are moved from one place to another. It ensures that products are available in the right place at the right time, which is crucial for meeting customer demand.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>30", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "WAREHOUSING : MEANING, TYPES AND DEFINITIONS", "question": "An example of a government warehouse is", "images": [], "options": {"A": "co-operative warehouse", "B": "bonded warehouse", "C": "manufacturer's warehouse", "D": "private warehouse"}, "answer": "B", "explanation": "A bonded warehouse is a secured warehouse facility that is covered by customs rules. Companies use these types of warehouses to store goods until duties or taxes are paid. It is typically controlled and supervised by the government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>31", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "WAREHOUSING : MEANING, TYPES AND DEFINITIONS", "question": "Which of the following goods are kept in bonded warehouse?", "images": [], "options": {"A": "Semi-finished goods", "B": "Dutiable goods", "C": "Consumer goods", "D": "Finished goods"}, "answer": "B", "explanation": "A bonded warehouse is a secured warehouse facility that is covered by customs rules. Companies use these types of warehouses to store their products before they have to pay any duties, or import taxes. In this case, the correct answer is 'Dutiable goods'. Dutiable goods are goods on which customs duty (a kind of tax) is due and has not been paid. Once the duty is paid, the goods can be released from the warehouse.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>32", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : MARKET UNIONS MEANING AND TYPES", "question": "A body that  comprises sellers of onions in an area is an example of a", "images": [], "options": {"A": "labour union", "B": "market union", "C": "employers' association", "D": "producers' association"}, "answer": "D", "explanation": "A body that comprises sellers of onions in an area is an example of a 'producers' association'. A producers' association is a group of producers who join together to promote and protect their common interests. They often work together to market their products, negotiate prices, and set standards for their industry. In this case, the sellers of onions have formed an association to promote their interests.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>33", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : MARKET FACILITATORS - MEANING, TYPES AND ROLES", "question": "An example of market facilitator is", "images": [], "options": {"A": "transportation companies", "B": "manufacturing companies", "C": "manufacturer's association", "D": "textile sellers association"}, "answer": "A", "explanation": "A market facilitator is an entity that helps make the market function more efficiently. This can include a wide range of organizations, including transportation companies, which help to move goods from producers to consumers. Therefore, 'transportation companies' is the correct answer. They facilitate the market by providing the necessary service of moving goods from one place to another, enabling trade and commerce.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>34", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL MARKETING : MEANING, IMPORTANCES AND REASONS", "question": "A method of engaging in international marketing with the lowest business risk is", "images": [], "options": {"A": "agency", "B": "exporting", "C": "joint venture", "D": "direct investment"}, "answer": "B", "explanation": "Exporting is a method of engaging in international marketing with the lowest business risk. This is because it does not require the company to establish a physical presence in the foreign market, thus reducing the risk of loss due to factors such as political instability, cultural differences, or economic downturns in the foreign market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>35", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL MARKETING : MEANING, IMPORTANCES AND REASONS", "question": "A form of engaging in international marketing that involves the pooling of resources between local and foreign firm is", "images": [], "options": {"A": "joint venture", "B": "direct investment", "C": "franchising", "D": "licencing"}, "answer": "A", "explanation": "A joint venture is a form of engaging in international marketing that involves the pooling of resources between a local and a foreign firm. In a joint venture, both firms share in the profits and losses of the venture, and both contribute resources such as capital, technology, or knowledge of the local market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>36", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "ICT IN MARKETING : E-MARKETING - MEANING, IMPORTANCE", "question": "One of the benefits of e-marketing is that is", "images": [], "options": {"A": "distributes company's goods", "B": "enhances product quality", "C": "broadens a company's customer base", "D": "prevents pilferage of company's goods"}, "answer": "C", "explanation": "One of the benefits of e-marketing is that it broadens a company's customer base. E-marketing, or electronic marketing, refers to the use of the internet and digital media to promote a company's products or services. This allows the company to reach a global audience, thus broadening its customer base.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>37", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "ICT IN MARKETING : E-MARKETING - MEANING, IMPORTANCE", "question": "One of the uses of e-marketing plaform is to", "images": [], "options": {"A": "deliver goods ordered", "B": "provide after sales service", "C": "provide packaging for products", "D": "promote goods and services"}, "answer": "D", "explanation": "E-marketing platforms are primarily used to promote goods and services. They allow businesses to reach a wider audience, engage with customers, and increase brand awareness. While some e-marketing platforms may facilitate the delivery of goods ordered or provide after-sales service, their primary function is to promote goods and services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>38", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : SELLING AND BARGAINING SKILLS", "question": "A skill a sales personnels should posses to enable him handle aggressive customer in a market outlet is", "images": [], "options": {"A": "calculate skill", "B": "management skill", "C": "bargaining skill", "D": "technical skill"}, "answer": "B", "explanation": "Management skills are crucial for a salesperson to handle aggressive customers in a market outlet. These skills include conflict resolution, problem-solving, and communication skills. While bargaining skills may be useful in a sales context, they are not specifically geared towards handling aggressive customers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2022>39", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "A factor to be considered in extending credit facilities to a customer is the", "images": [], "options": {"A": "nature of products to be sold", "B": "cost of producing the product", "C": "individual's total purchases in a given period", "D": "number of channel members involved in distribution"}, "answer": "C", "explanation": "When extending credit facilities to a customer, one of the factors to consider is the individual's total purchases in a given period. This helps to assess the customer's purchasing behavior and their ability to repay the credit. The nature of the products to be sold, the cost of producing the product, or the number of channel members involved in distribution do not directly influence the decision to extend credit to a customer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2022>40", "subject": "Marketing", "year": "2022", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : FACTORS AFFECTING LOCATION OF A MARKET OUTLET", "question": "An entrepreneur who intends to establish a frozen fish shop will need a", "images": [], "options": {"A": "reliable power supply", "B": "good communication network", "C": "good network of road", "D": "reliable skilled labour"}, "answer": "A", "explanation": "A frozen fish shop will need a reliable power supply to keep the fish frozen and prevent them from spoiling. This is more crucial than a good communication network, a good network of roads, or reliable skilled labour. While these are also important, without a reliable power supply, the primary function of the business (keeping fish frozen) cannot be achieved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>1", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : MEANING", "question": "The need for an item backed by the ability to pay by a consumer is", "images": [], "options": {"A": "demand", "B": "want", "C": "exchange", "D": "utility"}, "answer": "A", "explanation": "In marketing, the term 'demand' refers to the desire for a particular good or service backed by the ability and willingness to pay for it. Therefore, the need for an item backed by the ability to pay by a consumer is referred to as 'demand'. 'Want' is a desire for a product or service, 'exchange' is the act of obtaining a desired object from someone by offering something in return, and 'utility' is the satisfaction received from consuming a good or service.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>2", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "An orientation that holds that a company's decision should include consumer satisfaction and community development is", "images": [], "options": {"A": "societal marketing concept", "B": "production concept", "C": "product concept", "D": "selling product"}, "answer": "A", "explanation": "The societal marketing concept is an orientation that holds that a company's marketing decisions should consider consumers' wants, the company's requirements, consumers' long-run interests, and society's long-run interests. This concept suggests that the company's marketing strategy should deliver value to customers in a way that maintains or improves both the consumer's and society's well-being. The other options, production concept, product concept, and selling product, do not fully encompass this holistic approach.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>3", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "ADVERTISING : FUNCTIONS", "question": "The concept applied by XYZ Ltd that uses aggressive promotional efforts to attract customers to buy its brand of cosmetics is", "images": [], "options": {"A": "product concept", "B": "societal concept", "C": "selling concept", "D": "production concept"}, "answer": "C", "explanation": "The selling concept is a business notion which states that consumers will not buy enough of the firm's products unless it undertakes a large-scale selling and promotion effort. XYZ Ltd is using aggressive promotional efforts to attract customers to buy its brand of cosmetics, which aligns with the selling concept.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>4", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "ADVERTISING : FUNCTIONS", "question": "The proces of bringing products to the attention of prospective customers is", "images": [], "options": {"A": "distribution", "B": "promotion", "C": "labelling", "D": "branding"}, "answer": "B", "explanation": "Promotion is the process of bringing products to the attention of prospective customers. It involves communicating the benefits and value of your product to persuade potential customers to purchase it. This includes advertising, public relations, direct marketing, and sales promotion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>5", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : FACTORS AFFECTING MARKETING ENVIRONMENT", "question": "The factors that influence the performance of marketing activities of a firm is marketing", "images": [], "options": {"A": "orientation", "B": "intelligence", "C": "audit", "D": "environment"}, "answer": "D", "explanation": "The marketing environment includes the factors and forces that affect a firm's ability to build and maintain successful relationships with customers. It includes the internal environment (employees, customers, shareholders, retailers & distributors, etc.), the micro-environment (competitors, suppliers, etc.), and the macro-environment (political and legal environment, economic environment, socio-cultural environment, technological environment, etc.).", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>6", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : FACTORS AFFECTING MARKETING ENVIRONMENT", "question": "Which of the following factors would influence a company's decision to change its production process?", "images": [], "options": {"A": "Technological factor", "B": "Social factor", "C": "Political factor", "D": "Demographic factor"}, "answer": "A", "explanation": "Technological factors can greatly influence a company's decision to change its production process. This is because advancements in technology can lead to more efficient and cost-effective methods of production. For example, a company may decide to automate certain aspects of its production process to increase productivity and reduce labor costs. Therefore, technological factors are a key consideration in a company's decision to change its production process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>7", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : MEANING OF MARKETING MIX", "question": "The set of variables a confectionery company uses to execute its marketing strategy is marketing", "images": [], "options": {"A": "mix", "B": "plan", "C": "tactics", "D": "policy"}, "answer": "A", "explanation": "The set of variables a company uses to execute its marketing strategy is referred to as the marketing mix. The marketing mix is a business tool used in marketing and by marketers. The marketing mix is often crucial when determining a product or brand's offer, and is often associated with the 4 P's: price, product, promotion, and place.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>8", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "PRODUCTS : CLASSIFICATION", "question": "Iron ore is classified as", "images": [], "options": {"A": "secondary product", "B": "semi-finished product", "C": "consumer product", "D": "primary product"}, "answer": "D", "explanation": "Iron ore is classified as a primary product. Primary products are goods that are available from cultivating raw materials without a manufacturing process. In this case, iron ore is a type of raw material that is extracted from the earth and used in the production of iron and steel.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>9", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "PRODUCTS : CLASSIFICATION", "question": "Which of the following items is an example of primary product?", "images": [], "options": {"A": "Cotton", "B": "Handkerchief", "C": "Shirt", "D": "Head tie"}, "answer": "A", "explanation": "A primary product is a product in its raw form, before it has been processed or manufactured into a finished product. Cotton is a primary product as it is a raw material that can be processed into finished goods like clothes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>10", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "PRODUCTS : CLASSIFICATION", "question": "A product that is brought frequently on impulse at lower price is", "images": [], "options": {"A": "industrial goods", "B": "unsought goods", "C": "convenience goods", "D": "speciality goods"}, "answer": "C", "explanation": "Convenience goods are items that consumers purchase frequently, immediately, and with minimal effort. Therefore, a product that is bought frequently on impulse at a lower price is a convenience good.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>11", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MARKETS : MEANING", "question": "Use the following information to answer this question    OJ Ltd is a bakery that produces bread and confectioneries while Ernest Super Market buys its products.    OJ Ltd is an example of", "images": [], "options": {"A": "a consumer market", "B": "an industrial market", "C": "a government market", "D": "a reseller market"}, "answer": "B", "explanation": "An industrial market consists of all businesses or organizations that purchase products for use in the production of other goods or in their daily operations. Since Ernest Super Market buys its products, OJ Ltd is an example of an industrial market.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>12", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "Use the following information to answer this question    OJ Ltd is a bakery that produces bread and confectioneries while Ernest Super Market buys its products.    Ernest Super Market is classified as", "images": [], "options": {"A": "a retailer", "B": "a wholesaler", "C": "an agent", "D": "a producer"}, "answer": "A", "explanation": "Ernest Super Market is classified as a retailer because it buys products from producers (like OJ Ltd) and then sells them to the end consumers. A retailer is a business or person that sells goods to the consumer, as opposed to a wholesaler or supplier who would normally sell their goods to another business.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>13", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "The last stage in the buying decision process is the", "images": [], "options": {"A": "purhase decision", "B": "information search", "C": "post-purchase behaviour", "D": "evaluation of alternatives"}, "answer": "C", "explanation": "The last stage in the buying decision process is the post-purchase behaviour. This stage involves the consumer's feelings of satisfaction or dissatisfaction after the purchase of the product. It is at this stage that the consumer decides whether or not they are satisfied with the product and whether they would consider purchasing it again in the future.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>14", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : INFLUECING FACTORS", "question": "An organizational factor that influences a manager's decision to but raw materials from a particular source is company's", "images": [], "options": {"A": "reward system", "B": "structure", "C": "procedure", "D": "image"}, "answer": "C", "explanation": "An organizational factor that influences a manager's decision to buy raw materials from a particular source is the company's procedure. The company's procedure refers to the established way of doing things. This includes the process of selecting suppliers, which can be influenced by factors such as cost, quality, delivery time, and the supplier's reputation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>15", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "The systematic process of obtaining and analyzing data to provide information for marketing decision making is", "images": [], "options": {"A": "marketing research", "B": "marketing planning", "C": "market forecasting", "D": "market segmentation"}, "answer": "A", "explanation": "Marketing research is the systematic process of obtaining and analyzing data to provide information for marketing decision making. It involves the collection, analysis, and interpretation of data related to marketing products and services. The other options, marketing planning, market forecasting, and market segmentation, are all part of the broader marketing process, but they do not specifically involve the systematic collection and analysis of data.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>16", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : INFORMATION REQUIRED FOR MARKETING PLANNING", "question": "A source of primary data for marketing research is", "images": [], "options": {"A": "sales report", "B": "customer's feedback", "C": "inventory report", "D": "marketingg budget"}, "answer": "B", "explanation": "Primary data in marketing research is data that is collected directly from the source. This can include interviews, surveys, and customer feedback. Customer's feedback is a source of primary data because it comes directly from the customer, without any intermediary. The other options, sales report, inventory report, and marketing budget, are all examples of secondary data, which is data that has been collected and compiled by someone else.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>17", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "PRICING : PRICE DETERMINANTS", "question": "Which of the following factors is not a price determinant?", "images": [], "options": {"A": "Cost of production", "B": "Competitior's prices", "C": "Level of demand", "D": "Consumer's culture"}, "answer": "D", "explanation": "Price determinants are factors that influence the price of a product or service. These can include the cost of production, competitor's prices, and the level of demand. However, a consumer's culture is not a direct determinant of price. While culture can influence a consumer's willingness to pay for a product or service, it does not directly determine the price.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>18", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "PRICING : STRATEGIES", "question": "Which pricing strategy is adopted by a company that sells its product for ₦200 when the prevailing market price for same product is ₦150?", "images": [], "options": {"A": "Skimming pricing", "B": "Penetrating pricing", "C": "Psychological pricing", "D": "Competitive pricing"}, "answer": "A", "explanation": "Skimming pricing is a strategy where a high price is set for a product, especially when the product is new in the market or has unique features. In this case, the company is selling its product at a higher price (₦200) than the prevailing market price (₦150), which is a characteristic of skimming pricing.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>19", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "PRICING : STRATEGIES", "question": "Which of the following pricing strategies is used by wholesalers of industrial goods?", "images": [], "options": {"A": "Cost-plus pricing", "B": "Demand based pricing", "C": "Penetration pricing", "D": "Haggling pricing"}, "answer": "A", "explanation": "Cost-plus pricing is a strategy commonly used by wholesalers of industrial goods. This strategy involves adding a standard markup to the cost of the product to determine its selling price. This ensures that the wholesaler covers the cost of the product and makes a profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>20", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "Use the following information to answer this question    ABC Foods has recently expanded its production capacity and is searching for a medium for advertising its products at a lower cost.    Which of the folloewing advertising media would be suitable for the company?", "images": [], "options": {"A": "Television", "B": "Newspaper", "C": "Radio", "D": "Magazine"}, "answer": "C", "explanation": "Radio is a suitable medium for advertising products at a lower cost. Compared to television and magazines, radio advertising is generally less expensive. It also has a wide reach, making it an effective medium for a company that has recently expanded its production capacity and wants to reach a larger audience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>21", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "ADVERTISING : FUNCTIONS", "question": "Use the following information to answer this question    ABC Foods has recently expanded its production capacity and is searching for a medium for advertising its products at a lower cost.    A benefit the company would derive from advertising the product is", "images": [], "options": {"A": "increase in competition", "B": "increase in market share", "C": "decrease in production cost", "D": "decrease in tax liabilities"}, "answer": "B", "explanation": "Advertising is a marketing strategy that involves paying for space to promote a product, service, or cause. The actual promotional messages are called advertisements, or ads for short. The goal of advertising is to reach people most likely to be willing to pay for a company's products or services and entice them to buy. Therefore, one of the benefits a company would derive from advertising its product is an increase in market share. This is because advertising helps to increase the visibility of the product, attract new customers, and therefore increase the company's market share.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>22", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "Sales promotion is important because it enhables a business to", "images": [], "options": {"A": "fix prices for its products and services", "B": "locate customers in different areas", "C": "stimulate demand for its products", "D": "create competition between different products"}, "answer": "C", "explanation": "Sales promotion is one of the elements of the promotional mix. The primary elements in the promotional mix are advertising, personal selling, direct marketing and publicity/public relations. Sales promotion uses both media and non-media marketing communications for a pre-determined, limited time to increase consumer demand, stimulate market demand or improve product availability. Therefore, sales promotion is important because it stimulates demand for its products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>23", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "SALES PROMOTION : FORMS", "question": "A form of sales promotion that rewards customers for consistently purchasing a company;s product is", "images": [], "options": {"A": "loyalty scheme", "B": "quantity discount", "C": "promotional allowance", "D": "sales contest"}, "answer": "A", "explanation": "A loyalty scheme is a marketing strategy designed to encourage customers to continue to shop at or use the services of a business associated with the program. These programs exist covering most types of commerce, each one having varying features and rewards schemes. Therefore, a form of sales promotion that rewards customers for consistently purchasing a company's product is a loyalty scheme.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>24", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MERCHANDISING : MEANING", "question": "A person who carries out point-of-sales promotion is", "images": [], "options": {"A": "a wholesaler", "B": "a retailer", "C": "an agent", "D": "a merchandiser"}, "answer": "D", "explanation": "A merchandiser is the person who carries out point-of-sales promotion. They are responsible for the presentation of products in a way that prompts customers to make a purchase. This includes arranging product displays, pricing, and stocking. Wholesalers, retailers, and agents are all involved in the distribution process, but they do not typically handle point-of-sales promotions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>25", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "Which of the following institutions is not a marketing intermediary?", "images": [], "options": {"A": "Major distributors", "B": "Wholesalers", "C": "Financial firms", "D": "Retailers"}, "answer": "C", "explanation": "Financial firms are not considered marketing intermediaries. Marketing intermediaries, also known as middlemen or distribution intermediaries, are companies that help a company to sell its products, such as wholesalers, retailers, and major distributors. Financial firms, on the other hand, are institutions that provide financial services for its clients or members.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>26", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "ICT IN MARKETING : E-MARKETING - MEANING, IMPORTANCE", "question": "Use of the following information to answer this question    BIK Ltd has developed a new health application for the public.    Which of the following means would be used by the company to make the service available to the target market?", "images": [], "options": {"A": "Mail order business", "B": "Internet", "C": "Merchandising", "D": "Direct marketing"}, "answer": "B", "explanation": "The Internet would be the most effective means for BIK Ltd to make their new health application available to the public. Given that it's a digital product, it can be easily distributed online, either through the company's own website or through app stores. Mail order business, merchandising, and direct marketing are less effective for distributing digital products.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>27", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "Use of the following information to answer this question    BIK Ltd has developed a new health application for the public.  Which of the following illustrations would be used to distribute the application?", "images": [], "options": {"A": "Producer -------------> Consumer", "B": "Producer --------------> Retailer --------------------> Consumer", "C": "Producer ---------------> Wholesaler --------------> Retailer -------------->Consumer", "D": "Producer --------Agent ---------------Retailer -------------->Consumer"}, "answer": "A", "explanation": "The question is about the distribution of a digital product, a health application. Digital products are typically distributed directly from the producer to the consumer, without the need for intermediaries such as retailers or wholesalers. This is because digital products can be easily and instantly delivered over the internet. Therefore, the correct illustration of the distribution would be 'Producer -------------> Consumer'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>28", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "TRANSPORTATION : MEANING,MODE, CHOICE AND IMPORTANCE", "question": "Air transport is preferred to other modes because it is", "images": [], "options": {"A": "faster in transporting goods for long distance", "B": "relatively cheaper than other modes", "C": "affected by weather conditions", "D": "suitable for door-to-door services"}, "answer": "A", "explanation": "Air transport is often preferred for long-distance transportation because it is faster than other modes of transport such as road, rail, or sea. While air transport can be affected by weather conditions and is not suitable for door-to-door services, its speed is a significant advantage, especially for perishable goods or when time is a critical factor. Therefore, the statement 'faster in transporting goods for long distance' is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>29", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "TRANSPORTATION : FACTORS AFFECTING CHOICE OF TRANSPORTATION", "question": "Which of the following factors would not be considered by a cement manufacturing firm in the choice of transportation mode for its goods?", "images": [], "options": {"A": "Cost of the mode", "B": "Quantity of the product", "C": "Availability of the mode", "D": "Government policies"}, "answer": "D", "explanation": "When a cement manufacturing firm is choosing a mode of transportation for its goods, it would consider factors such as the cost of the mode, the quantity of the product, and the availability of the mode. However, government policies would not directly affect the choice of transportation mode. Government policies might affect aspects of the manufacturing process or the sale of the product, but they would not typically dictate or influence the choice of transportation mode. Therefore, the factor that would not be considered is 'Government policies'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>30", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "WAREHOUSING : ACTIVITIES IN THE WAREHOUSING", "question": "An activity performed in a warehouse is", "images": [], "options": {"A": "production of goods", "B": "sorting and labelling", "C": "repairs and maintenance", "D": "purchasing of raw materials"}, "answer": "B", "explanation": "A warehouse is a building for storing goods. Warehouses are used by manufacturers, importers, exporters, wholesalers, transport businesses, customs, etc. They are usually large plain buildings in industrial parks on the outskirts of cities, towns, or villages. They usually have loading docks to load and unload goods from trucks. Sometimes warehouses are designed for the loading and unloading of goods directly from railways, airports, or seaports. They often have cranes and forklifts for moving goods, which are usually placed on ISO standard pallets loaded into pallet racks. Stored goods can include any raw materials, packing materials, spare parts, components, or finished goods associated with agriculture, manufacturing, or commerce. The key activities performed in a warehouse include receiving, put away, storage, picking, packing, and shipping. Sorting and labelling is part of these key activities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>31", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "WAREHOUSING : MEANING, TYPES AND DEFINITIONS", "question": "A specialised facility used for the storage of fruits and vegetables is", "images": [], "options": {"A": "refrigerator", "B": "barn", "C": "silo", "D": "tank"}, "answer": "A", "explanation": "A refrigerator is a specialized facility used for the storage of fruits and vegetables. It is an appliance that is designed to eliminate heat and so lower the temperature of its contents, and to maintain a temperature below the ambient temperature of the room. This slows down the natural biological processes that take place in food and other perishable goods, and so prolongs the period in which such goods are fit for consumption. A barn is a large farm building used for storing grain, hay, or straw or for housing livestock. A silo is a tall tower or pit on a farm used to store grain. A tank is a large, often metallic, container for holding or storing liquids or gases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>32", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : MARKET UNIONS MEANING AND TYPES", "question": "Use the following information to answer the question    The yam sellers in Alesinloye trading area in Kano formed an organization.    What type of organization formed by the yam sellers is a", "images": [], "options": {"A": "trade union", "B": "market operator", "C": "market union", "D": "trade association"}, "answer": "C", "explanation": "A market union is an organization formed by traders in a particular market, often for the purpose of promoting their collective interests, maintaining standards, and addressing issues that affect them. In this case, the yam sellers in Alesinloye trading area in Kano have formed an organization, which is likely to be a market union. A trade union is an organization of workers who have come together to achieve common goals such as protecting the integrity of its trade, improving safety standards, and attaining better wages and benefits such as health care and retirement, increasing the number of employees an employer assigns to complete the work, and better working conditions. A market operator is a company that operates a physical or virtual marketplace for trading securities, commodities, derivatives, or other financial instruments. A trade association, also known as an industry trade group, business association, sector association or industry body, is an organization founded and funded by businesses that operate in a specific industry.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>33", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : ROLES OF MARKET UNIONS", "question": "Use the following information to answer the question    The yam sellers in Alesinloye trading area in Kano formed an organization.    Which of the following functions would be performed by the organization?", "images": [], "options": {"A": "Provision of overdraft to members", "B": "Rendering security services to members", "C": "Provision of employment to members", "D": "Disseminating information to members"}, "answer": "D", "explanation": "The organization formed by the yam sellers in Alesinloye trading area in Kano would likely perform the function of disseminating information to members. This could include information about market trends, prices, and other relevant news. This is a common function of trade organizations, which exist to support and advocate for their members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>34", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : ROLES OF MARKET UNIONS", "question": "Use the following information to answer the question    The yam sellers in Alesinloye trading area in Kano formed an organization.    Which of the following reasons would have informed the formation of the association? To", "images": [], "options": {"A": "advertise goods for producers", "B": "provide warehouse facilities to producers", "C": "protect the interest of members", "D": "provide insurance services to members"}, "answer": "C", "explanation": "The reason for the formation of the association by the yam sellers in Alesinloye trading area in Kano would likely be to protect the interest of members. This could include advocating for fair trade practices, negotiating better terms with suppliers, or lobbying for favorable policies. This is a common reason for the formation of trade associations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>35", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : MEANING OF ENTREPRENEURSHIP", "question": "Use the following information to answer this question    Muyi sets up a poultry business at the outskirts of Oshogbo upon retirement from the civil service.    Muyi is regarded as", "images": [], "options": {"A": "a broker", "B": "a retailer", "C": "an agent", "D": "an entrepreneur"}, "answer": "D", "explanation": "Muyi, who sets up a poultry business at the outskirts of Oshogbo upon retirement from the civil service, is regarded as an entrepreneur. An entrepreneur is a person who sets up a business or businesses, taking on financial risks in the hope of profit. In this case, Muyi is taking on the financial risk of setting up a poultry business in the hope of making a profit.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>36", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : FACTORS AFFECTING LOCATION OF A MARKET OUTLET", "question": "Use the following information to answer this question    Muyi sets up a poultry business at the outskirts of Oshogbo upon retirement from the civil service.    Which of the following factors would have influenced the choice of the location of the poultry business?", "images": [], "options": {"A": "Nearness to the market", "B": "Nearness to financial institution", "C": "Government policy", "D": "Accessibility to good roads"}, "answer": "A", "explanation": "The location of a business is often influenced by several factors. In the case of a poultry business, nearness to the market is a crucial factor. This is because poultry products are perishable and need to be sold quickly to avoid losses. Therefore, being close to the market would allow Muyi to sell his products faster and reduce the risk of spoilage. Other options like nearness to financial institution, government policy, and accessibility to good roads are also important but not as critical as the nearness to the market in this context.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>37", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : SOURCES OF FUNDS", "question": "A source of financing option available to a provision store owner is", "images": [], "options": {"A": "sale of shares", "B": "issue of debentures", "C": "leasing", "D": "personal savings"}, "answer": "D", "explanation": "A provision store owner, who is typically a small business owner, would most likely use personal savings as a source of financing. This is because other options like sale of shares, issue of debentures, and leasing are more applicable to larger corporations. Personal savings is a common source of financing for small businesses as it does not require any formal application or approval process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>38", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "TRANSPORTATION : DOCUMENTS USED IN TRANSPORTATION", "question": "A delivery note that accompanies goods to the buyer shows", "images": [], "options": {"A": "price of goods bought", "B": "quality of goods bought", "C": "quantity of goods bought", "D": "discount on goods bought"}, "answer": "C", "explanation": "A delivery note is a document that accompanies goods delivered to a buyer. It serves as proof of delivery and typically shows the quantity of goods bought. It does not usually include information about the price, quality, or any discount on the goods. These details are usually included in the invoice, not the delivery note.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2023>39", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "PRODUCTS : PRODUCT DESIGN", "question": "Use the information below to answer this question          The inscription V-Cough on the product is an example of a", "images": ["Marketing/imgs/2023/cough.png"], "options": {"A": "trademark", "B": "brand name", "C": "patent", "D": "copyright"}, "answer": "B", "explanation": "The inscription \"V-Cough\" on the product is an example of a brand name.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2023>40", "subject": "Marketing", "year": "2023", "type": "Objective", "topic": "PRODUCTS : PRODUCT DESIGN", "question": "Use the information below to answer this question        The part represented by the letter Z is the", "images": ["Marketing/imgs/2023/cough.png"], "options": {"A": "brand", "B": "package", "C": "label", "D": "copyright"}, "answer": "B", "explanation": "The part labelled Z is package.  In marketing, a package refers to the physical container or wrapping that holds a product. It includes the design, materials, and functionality of the container, as well as any labeling or branding elements. The package plays a crucial role in attracting consumers, communicating the product's value proposition, and protecting the product during storage and transportation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>1", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "INTRODUCTION TO MARKETING : MEANING OF MARKETING", "question": "The process of identifying needs, delivering and exchanging products that have value for customers is", "images": [], "options": {"A": "sales", "B": "distribution", "C": "marketing", "D": "advertising"}, "answer": "C", "explanation": "Marketing involves the process of identifying consumer needs and wants, creating products or services that satisfy those needs, promoting and delivering those products or services, and facilitating their exchange with customers in a way that creates value for both the customer and the business. It encompasses activities such as market research, product development, pricing, distribution, promotion (which includes advertising), and customer service.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>2", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "INTRODUCTION TO MARKETING : FUNCTIONS", "question": "Which of the following activities is a function of marketing?", "images": [], "options": {"A": "Advertising", "B": "Production", "C": "Store Keeping", "D": "Maintenance"}, "answer": "A", "explanation": "Advertising is a specific activity within the broader function of marketing. Marketing encompasses a range of activities aimed at identifying customer needs, developing products or services to meet those needs, promoting and communicating the value of those products or services to customers, and facilitating their exchange. Advertising is one of the promotional tools used in marketing to communicate with and persuade target audiences about products or services. It involves creating and placing advertisements in various media to reach potential customers and influence their purchasing decisions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>3", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "The business concept that states consumers would buy any item once it is of high quality is", "images": [], "options": {"A": "marketing concept", "B": "production concept", "C": "selling concept", "D": "product concept"}, "answer": "D", "explanation": "The product concept emphasizes that consumers will favour products that offer the most in quality, performance, and innovative features. This concept assumes that consumers are primarily interested in product availability and quality and will buy the product that offers the most quality, performance, or innovative features available in the market. It focuses on continuous product improvement and innovation to meet or exceed customer expectations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>4", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "The concept applied by ABC Ltd if it analyses its customer's needs before providing goods to satisfy them is", "images": [], "options": {"A": "production concept", "B": "product concept", "C": "selling concept", "D": "marketing concept"}, "answer": "D", "explanation": "The marketing concept focuses on identifying and understanding the needs and wants of customers and then providing goods and services that satisfy those needs effectively. It involves researching customer preferences, behaviors, and demands to develop products or services that meet their expectations and provide value. By analyzing customer needs before delivering goods, ABC Ltd would be aligning with the marketing concept, which emphasizes customer orientation and satisfaction as key drivers of business success.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>5", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : ELEMENT", "question": "A component of place as a marketing mix element is", "images": [], "options": {"A": "warrantee", "B": "packaging", "C": "warehouse", "D": "discount"}, "answer": "C", "explanation": "In the marketing mix, also known as the 4Ps (Product, Price, Place, Promotion), \"place\" refers to the distribution channels and locations where products or services are made available to customers. It involves decisions related to how products are accessed by the target market, including distribution channels, logistics, and physical locations such as warehouses, retail outlets, and online platforms.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>6", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : FACTORS AFFECTING LOCATION OF A MARKET OUTLET", "question": "The environment factor that influenced the relocation of a company from Lagos to Kano a a result of high taxes and levies is", "images": [], "options": {"A": "religious factor", "B": "technological factor", "C": "political factor", "D": "social factor"}, "answer": "C", "explanation": "High taxes and levies imposed by the government are directly related to political decisions and policies. These financial burdens can significantly affect a company's profitability and operational costs. When a company decides to relocate to a different area to escape these high taxes and levies, it is responding to political factors such as government taxation policies and regulations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>7", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : ELEMENT", "question": "An element of the marketing mix that deals with storage of goods is", "images": [], "options": {"A": "product", "B": "price", "C": "place", "D": "promotion"}, "answer": "C", "explanation": "The \"place\" element of the marketing mix refers to the distribution aspect of marketing. This includes the logistics of getting the product to the customer, which encompasses warehousing and storage of goods. Ensuring products are stored properly and available at the right locations is a crucial part of the distribution strategy, making \"place\" the correct answer.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>8", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "PRODUCTS : PRODUCT DESIGN", "question": "A part of a product with primary function of protecting the content is the", "images": [], "options": {"A": "brand name", "B": "trademark", "C": "container", "D": "label"}, "answer": "C", "explanation": "The container of a product is specifically designed to protect its contents from damage, contamination, and spoilage. It serves as the physical barrier that keeps the product safe during storage, transportation, and handling, ensuring it reaches the consumer in good condition.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>9", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "PRODUCTS : DISTINCTION BETWEEN CLASSES OF PRODUCTS", "question": "Which of the following categories of products is classified based on usage?", "images": [], "options": {"A": "Mineral and non-mineral products", "B": "Consumer and industrial goods", "C": "Oil and non-oil products", "D": "Goods and services"}, "answer": "B", "explanation": "Consumer and industrial goods are categories of products classified based on their usage:  - Consumer goods are products purchased by individuals for personal use or consumption.  -  Industrial goods are products used by businesses to produce other goods or services.    This classification is based on how the products are utilized rather than their nature (like mineral vs. non-mineral or oil vs. non-oil).", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>10", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "PRODUCTS : CLASSIFICATION", "question": "Lubricants purchased by a firm and used up in their cause of operations are classified as", "images": [], "options": {"A": "consumer products", "B": "industrial products", "C": "specialty goods", "D": "unsought goods"}, "answer": "B", "explanation": "Industrial products are goods purchased by businesses and organizations for use in their operations or to support production processes. Lubricants, which are used in machinery and equipment to reduce friction and wear, fall under this category. They are not meant for personal consumption but rather for industrial or business use, making \"industrial products\" the correct classification for lubricants.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>11", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "MARKETS : CLASSIFICATION", "question": "Market is broadly classified as", "images": [], "options": {"A": "consumer and organizational markets", "B": "retail and wholesale markets", "C": "consumer and wholesale markets", "D": "industrial and government markets"}, "answer": "A", "explanation": "The classification of markets broadly divides them into two main categories:  -   Consumer markets: These involve individuals or households who purchase goods and services for personal use.  -   Organizational markets (also known as business or industrial markets): These involve businesses, institutions, and governments that purchase goods and services to use in their operations or to resell.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>12", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "MARKETS : CLASSIFICATION", "question": "Which of the following buyers of products are classified as consumer market?", "images": [], "options": {"A": "Industries", "B": "Retailers", "C": "Households", "D": "Governments"}, "answer": "C", "explanation": "Consumer markets consist of individuals or households who purchase goods and services for personal consumption. This distinguishes them from organizational markets (such as industries, retailers, and governments) which purchase goods and services for business use, resale, or public services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>13", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : MEANING", "question": "Cognitive dissonance occurs when a customer", "images": [], "options": {"A": "is satisfied with a product", "B": "is dissatisfied with a product", "C": "re-buys a product", "D": "recommends a product"}, "answer": "B", "explanation": "Cognitive dissonance refers to the discomfort or tension that arises when there is inconsistency between a person's beliefs or attitudes and their behavior. In the context of consumer behavior, cognitive dissonance occurs when a customer experiences discomfort or uncertainty after making a purchase decision, especially if they perceive inconsistencies between their expectations and their actual experience with the product.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>14", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : INFLUECING FACTORS", "question": "A consumer's buying behaviour is influenced by", "images": [], "options": {"A": "professional opinion", "B": "reference group", "C": "company's strategy", "D": "company's plan"}, "answer": "B", "explanation": "Reference groups are social groups that influence the attitudes, beliefs, and behaviors of an individual. Consumers often look to reference groups for guidance and validation when making purchasing decisions. These groups can include family, friends, colleagues, or other social networks. Their opinions, preferences, and behaviors can significantly influence how a consumer evaluates products and brands, shaping their buying decisions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>15", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "The first step in the marketing research process is", "images": [], "options": {"A": "data analysis", "B": "problem definition", "C": "collection of data", "D": "reporting of findings"}, "answer": "B", "explanation": "Before any data is collected, analyzed, or reported, it is essential to clearly define the problem or objective of the research. This involves identifying the specific issue or question that the research aims to address. Without a well-defined problem, it is difficult to conduct effective research and interpret the findings correctly.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>16", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : INFORMATION REQUIRED FOR MARKETING PLANNING", "question": "Which of the following information would be relevant in marketing research for industrial goods?", "images": [], "options": {"A": "Consumption pattern", "B": "Lifestyle of consumers", "C": "Product life- cycle", "D": "Size of the product"}, "answer": "A", "explanation": "Industrial goods are purchased by businesses and organizations for use in their operations or for resale. Understanding the consumption pattern of these goods among industrial buyers is crucial for marketing research. This includes how frequently the goods are purchased, in what quantities, and for what purposes. It helps businesses tailor their marketing strategies and product offerings to better meet the needs and preferences of industrial customers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>17", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "PRICING : STRATEGIES", "question": "Use the following information to answer the question    KPKC Ltd bought 60 packs of beverages at #150 each and sold at a 20% mark up.    The pricing strategy adopted by KPKC Ltd is", "images": [], "options": {"A": "demand based pricing", "B": "penetration pricing", "C": "skimming pricing", "D": "cost-plus pricing"}, "answer": "D", "explanation": "Cost-plus pricing involves setting a price by adding a markup to the cost of the product. In this case, KPKC Ltd purchased the beverages at ₦150 each and then added a 20% markup to determine the selling price. This strategy ensures that the company covers its costs and earns a profit margin on each sale.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>18", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "PRICING : STRATEGIES", "question": "Use the following information to answer the question    KPKC Ltd bought 60 packs of beverages at #150 each and sold at a 20% mark up.    The total cost of the beverages is", "images": [], "options": {"A": "#1,800", "B": "#7,200", "C": "#9,000", "D": "#10,800"}, "answer": "C", "explanation": "KPKC Ltd bought 60 packs of beverages at ₦150 each.    Totl cost = 60 x 150  = #9,000", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>19", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "PRICING : STRATEGIES", "question": "Use the following information to answer the question    KPKC Ltd bought 60 packs of beverages at #150 each and sold at a 20% mark up.    The selling price per pack is", "images": [], "options": {"A": "#30", "B": "#120", "C": "#150", "D": "#180"}, "answer": "D", "explanation": "Mark up = Cost price  x Percentage Mark up  = 150  x 20%  = #30    Selling Price = Cost price + Mark up  = 150 + 30  = #180", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>20", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "An advantage of using radio as a medium of advertising is that it has", "images": [], "options": {"A": "wide geographical coverage", "B": "visual and motion effect", "C": "unlimited time availability", "D": "long lasting effect"}, "answer": "A", "explanation": "Radio advertising reaches a wide geographical area because radio signals can cover large regions, including rural and remote areas where other forms of media might not reach as effectively. This wide coverage allows advertisers to reach diverse audiences across different locations, making radio a powerful medium for regional or national advertising campaigns.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>21", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "Newspapers, magazines and pamphlets are examples of", "images": [], "options": {"A": "electronic media", "B": "print media", "C": "social media", "D": "broadcast media"}, "answer": "B", "explanation": "Print media refers to forms of mass communication that are printed and distributed physically, such as newspapers, magazines, pamphlets, and books. These mediums use ink on paper or other materials to convey information to readers. Print media have been traditionally significant in advertising, journalism, and publishing industries.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>22", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "SALES PROMOTION : FORMS", "question": "Use the following information to answer the question    ABC Bakery has decided to implement an incentive scheme to encourage bulk buying due to low sales affecting the company    The discount that is suitable for the company to achieve its objectives is", "images": [], "options": {"A": "seasonal discount", "B": "cash discount", "C": "functional discount", "D": "quatity discount"}, "answer": "D", "explanation": "Quantity discounts are discounts offered to customers who purchase large quantities of a product. This type of discount is particularly effective in encouraging bulk buying because it incentivizes customers to buy more in order to receive a lower price per unit. Given that ABC Bakery wants to stimulate sales by encouraging larger purchases, a quantity discount aligns with their objective of boosting sales volume through bulk buying incentives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>23", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "SALES PROMOTION : FORMS", "question": "Use the following information to answer the question    ABC Bakery has decided to implement an incentive scheme to encourage bulk buying due to low sales affecting the company    Another sale proportional incentive the company could adopt to stimulate sales is", "images": [], "options": {"A": "advertising", "B": "public relations", "C": "free samples", "D": "personal selling"}, "answer": "C", "explanation": "Offering free samples is a sales promotion technique where customers are given a small amount of a product for free to encourage them to try and potentially purchase more of the product. In the case of ABC Bakery, offering free samples of their baked goods could entice customers to try their products and potentially buy larger quantities if they like what they sample. This approach directly encourages sales through a proportional incentive (free samples leading to potential bulk purchases).", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>24", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "PRODUCTS : PRODUCT DESIGN", "question": "The process of designing and producing containers and wrappers for a product is", "images": [], "options": {"A": "packaging", "B": "branding", "C": "labelling", "D": "sorting"}, "answer": "A", "explanation": "Packaging involves the design and production of containers, wrappers, and other materials that protect and enclose a product. It includes considerations such as functionality, aesthetics, safety, and convenience for both storage and use. Packaging plays a crucial role in product marketing by influencing consumer perception and attracting attention on store shelves.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>25", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "A channel member responsible for bulk breaking is the", "images": [], "options": {"A": "producer", "B": "agent", "C": "consumer", "D": "wholesaler"}, "answer": "D", "explanation": "Wholesalers typically buy goods in bulk from manufacturers or producers and then break down the bulk into smaller units for resale to retailers or directly to consumers. They play a crucial role in the distribution channel by providing a convenient way for retailers to access a wide range of products in smaller quantities, thus facilitating the movement of goods from producers to end consumers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>26", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "A highly priced industrial product would be distributed using", "images": [], "options": {"A": "indirect channel", "B": "intensive distribution", "C": "direct channel", "D": "selective distribution"}, "answer": "D", "explanation": "Selective distribution involves selling products through a limited number of outlets in specific geographical areas. This distribution strategy is often chosen for products that are highly priced, specialized, or require personalized selling efforts. Industrial products, especially those with higher prices and specialized uses, often benefit from selective distribution because it allows for better control over product positioning, ensures adequate support and service, and maintains a certain level of exclusivity in the market.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>27", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "The use of private retail outlets in the sales and distribution of petroleum products in Nigeria is an example of", "images": [], "options": {"A": "direct distribution", "B": "selective distribution", "C": "indirect distribution", "D": "exclusive distribution"}, "answer": "B", "explanation": "Selective distribution involves selling products through a limited number of outlets that meet specific criteria. In the case of petroleum products in Nigeria, these products are distributed through private retail outlets that have been selected based on certain standards and agreements. This approach allows for better control over product quality, branding, and customer service at these outlets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>28", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "TRANSPORTATION : DOCUMENTS USED IN TRANSPORTATION", "question": "A document that contains information relating to goods being transported is", "images": [], "options": {"A": "waybill", "B": "receipt", "C": "licence", "D": "invoice"}, "answer": "A", "explanation": "A waybill is a document that accompanies goods during shipment and provides details about the goods being transported, such as quantity, description, destination, and consignor (sender) and consignee (receiver) information. It serves as a legal document and proof of shipment, ensuring that the goods are delivered to the correct destination and received by the intended recipient.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>29", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "Which of the following distribution methods is used by  a sachet water company that sells its products to households?", "images": [], "options": {"A": "Indirect distribution", "B": "Exclusive distribution", "C": "Direct distribution", "D": "Intensive distribution"}, "answer": "C", "explanation": "Direct distribution involves selling products directly from the producer to the consumer without intermediaries. In the case of a sachet water company, they typically sell their products directly to households through their own distribution network or directly from their production facilities. This approach allows them to maintain control over product quality, pricing, and customer relationships.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>30", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "PRODUCTS : PRODUCT DESIGN", "question": "The process of attaching or printing information about a product on the package is", "images": [], "options": {"A": "branding", "B": "labelling", "C": "designing", "D": "cataloguing"}, "answer": "B", "explanation": "Labelling refers to the process of attaching or printing information, such as product details, ingredients, usage instructions, and safety warnings, on the package of a product. It serves to inform consumers about the product, provide necessary legal and regulatory information, and aid in product identification.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>31", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "TRANSPORTATION : MEANING,MODE, CHOICE AND IMPORTANCE", "question": "A function of marketing that deals with the movement of goods and salesmen from one location to another is", "images": [], "options": {"A": "warehousing", "B": "transportation", "C": "distribution", "D": "promotion"}, "answer": "B", "explanation": "Transportation in marketing refers to the physical movement of goods from the point of production to the point of consumption. It also involves the movement of sales personnel or salesmen to different locations to engage with customers and promote products. Transportation ensures that products are delivered efficiently and timely to customers or distribution centers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>32", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL MARKETING : INFLUENCING FACTORS", "question": "Use the following information to answer the question.    Saka Ltd has decided to engage in international marketing but wants to minimize the risk involved.    Which of the following reasons would have influenced the company's decision?", "images": [], "options": {"A": "Increase regulation in the foreign market", "B": "High labour cost in the foreign market", "C": "Low demand in domestic market", "D": "Availability of subsidies in domestic market"}, "answer": "A", "explanation": "Entering international markets can involve various risks, including regulatory challenges that differ from domestic markets. Increased regulations in foreign markets can create complexities and uncertainties for businesses unfamiliar with local laws and compliance requirements. Minimizing risk in international marketing often involves careful consideration of regulatory environments to ensure legal compliance and mitigate potential penalties or operational disruptions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>33", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL MARKETING : GUIDING RULES AND REGULATIONS", "question": "Use the following information to answer the question.    Saka Ltd has decided to engage in international marketing but wants to minimize the risk involved.    The mode of entry that would be suitable for the company is", "images": [], "options": {"A": "exporting", "B": "direct investment", "C": "joint venture", "D": "licensing"}, "answer": "A", "explanation": "Exporting involves selling products produced in the company's home country to customers in foreign markets. It allows Saka Ltd to enter international markets with relatively low financial and operational risk compared to other modes of entry like direct investment, joint ventures, or licensing. By exporting, Saka Ltd can test international markets, gain market knowledge, and gradually expand its presence without significant upfront investments or commitments abroad.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>34", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : MARKET UNIONS MEANING AND TYPES", "question": "An associations of traders belonging to the same line of business is a", "images": [], "options": {"A": "cooperative society", "B": "merchant association", "C": "market facilitator", "D": "market union"}, "answer": "B", "explanation": "A merchant association is an organization formed by traders or merchants who operate in the same industry or line of business. These associations often collaborate to address common issues, advocate for their interests, and promote industry standards and practices. They may also facilitate networking opportunities, provide collective bargaining power, and support their members in various business activities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>35", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL MARKETING : MEANING, IMPORTANCES AND REASONS", "question": "The process of entering a new market by paying a fee for using another company's brand name is", "images": [], "options": {"A": "exporting", "B": "licensing", "C": "direct ownership", "D": "joint venture"}, "answer": "B", "explanation": "Licensing is a business arrangement where one company (the licensor) grants another company (the licensee) the right to use its intellectual property, such as brand names, trademarks, patents, or technology, for a specified period and under certain conditions in exchange for a fee or royalty. This allows the licensee to enter a new market using the established brand name of the licensor, leveraging their brand recognition and reputation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>36", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "ICT IN MARKETING : E-MARKETING - MEANING, IMPORTANCE", "question": "Ernest Ltd's efforts to promote and sell its fruit juice through the company's website is an example of", "images": [], "options": {"A": "e-payment", "B": "e-marketing", "C": "e-procurement", "D": "e-transaction"}, "answer": "B", "explanation": "E-marketing refers to the use of digital technologies and online platforms to promote products or services, attract customers, and drive sales. By promoting and selling its fruit juice through its website, Ernest Ltd is engaging in e-marketing activities. This includes using the website for advertising, creating online promotions, interacting with customers through social media, and facilitating online sales transactions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>37", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "SALES PROMOTION : FORMS", "question": "Services offered to customers by a firm to encourage continuous patronage of the company's products is", "images": [], "options": {"A": "pre-sale services", "B": "after-sales service", "C": "self-services", "D": "merchandising services"}, "answer": "B", "explanation": "After-sales service refers to the support and assistance provided by a company to customers after they have purchased a product. This includes services such as installation, maintenance, repair, warranties, technical support, and customer service. By offering excellent after-sales service, a company aims to enhance customer satisfaction, build loyalty, and encourage repeat purchases.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>38", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : MARKET FACILITATORS - MEANING, TYPES AND ROLES", "question": "Mr John who identified people's need for pop-corn and met it at a profit is a", "images": [], "options": {"A": "researcher", "B": "factor", "C": "marketer", "D": "facilitator"}, "answer": "C", "explanation": "A marketer identifies consumer needs or demands and develops products or services to meet those needs profitably. In this scenario, Mr. John recognized the demand for popcorn (a consumer need) and fulfilled it by providing popcorn at a profit. This aligns with the role of a marketer, who not only identifies market opportunities but also creates value by satisfying consumer needs through effective product development, pricing, promotion, and distribution strategies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2024>39", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "TRANSPORTATION : MEANING,MODE, CHOICE AND IMPORTANCE", "question": "A factor that would be considered in the choice of transportation mode is", "images": [], "options": {"A": "location of customers", "B": "product brand", "C": "government policy", "D": "reliability of the menas"}, "answer": "A", "explanation": "The location of customers is a crucial factor in determining the appropriate transportation mode. Different transportation modes (such as road, rail, air, or sea) have varying capabilities and efficiencies in reaching different geographical locations. Factors such as distance, accessibility, infrastructure, and customer proximity influence the choice of transportation mode.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2024>40", "subject": "Marketing", "year": "2024", "type": "Objective", "topic": "MARKETS : CLASSIFICATION", "question": "One of the distinctive feature of a supermarket is", "images": [], "options": {"A": "pre-packaging of goods", "B": "after-sales services", "C": "credit sales", "D": "self service"}, "answer": "D", "explanation": "Supermarkets are characterized by the concept of self-service, where customers select and retrieve products from shelves or displays without the assistance of sales personnel. This allows customers to browse freely, compare products, and make selections independently. Self-service is a fundamental aspect of the supermarket model, promoting efficiency, convenience, and customer autonomy in the shopping experience.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>1", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "INTRODUCTION TO MARKETING : MEANING OF MARKETING", "question": "The business activity concerned with the identification and satisfaction of consumers' needs is", "images": [], "options": {"A": "merchandising", "B": "sales promotion", "C": "production management", "D": "marketing"}, "answer": "D", "explanation": "The business activity concerned with the identification and satisfaction of consumers' needs is known as marketing. Marketing encompasses various activities aimed at understanding consumer needs and delivering products or services that meet those needs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>2", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETING CONCEPTS : MARKETING CONCEPTS", "question": "The concept that states that consumers will only buy goods that are available and affordable is the", "images": [], "options": {"A": "marketing concept", "B": "product concept", "C": "selling concept", "D": "production concept"}, "answer": "D", "explanation": "The concept that states that consumers will only buy goods that are available and affordable is the production concept. This concept emphasizes that consumers will favor products that are available and highly affordable, leading businesses to focus on production efficiency.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>3", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : MEANING OF MARKETING MIX", "question": "The element of marketing mix that involves the creation of awareness is", "images": [], "options": {"A": "place", "B": "price", "C": "product", "D": "promotion"}, "answer": "D", "explanation": "The element of the marketing mix that involves the creation of awareness is promotion. Promotion includes various activities such as advertising, sales promotions, and public relations that aim to inform and persuade potential customers about products or services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>4", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : FACTORS AFFECTING MARKETING ENVIRONMENT", "question": "Minimum wage as an environmental factor is associated with", "images": [], "options": {"A": "political factor", "B": "technological factor", "C": "economic factor", "D": "social factor"}, "answer": "C", "explanation": "Minimum wage as an environmental factor is associated with the economic factor. Economic factors include elements that affect the economy's performance, such as wage levels, which can influence consumer purchasing power and overall market conditions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>5", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETING CONCEPTS : MEANING", "question": "The emphasis of societal marketing concept is on", "images": [], "options": {"A": "firm's profitability", "B": "environmental safety", "C": "product improvement", "D": "employee satisfaction"}, "answer": "B", "explanation": "The emphasis of the societal marketing concept is on environmental safety. This concept extends beyond traditional marketing by considering the well-being of society and the environment, encouraging businesses to operate sustainably and ethically.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>6", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "PRODUCTS : MEANING", "question": "Limestone as a raw material in cement production is an example of", "images": [], "options": {"A": "primary product", "B": "oil based product", "C": "secondary product", "D": "manufactured product"}, "answer": "A", "explanation": "Limestone is a naturally occurring mineral that is extracted and used directly in the production of cement. It is considered a primary product because it is a raw material that is used in its natural state without any significant processing.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>7", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "PRODUCTS : CLASSIFICATION", "question": "A tractor bought for use by a farmer is an example of", "images": [], "options": {"A": "industrial goods", "B": "convenience goods", "C": "consumer goods", "D": "unsought goods"}, "answer": "A", "explanation": "A tractor bought for use by a farmer is classified as an industrial good because it is a durable good used in the production of other goods (in this case, agricultural products). Industrial goods are typically used in the production process rather than for personal consumption.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>8", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : MEANING", "question": "A feature of the consumer market is that", "images": [], "options": {"A": "there are few buyers", "B": "there are many buyers", "C": "professional services are required", "D": "high purchase volume is involved"}, "answer": "B", "explanation": "A feature of the consumer market is that there are many buyers. This is in contrast to industrial markets, which typically have fewer buyers but larger transactions. The consumer market is characterized by a large number of individual consumers purchasing goods and services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>9", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "The stage at which product requirement is prescribed in an organization's buying decision process is", "images": [], "options": {"A": "need identification", "B": "need specification", "C": "supplier search", "D": "supplier evaluation"}, "answer": "B", "explanation": "The stage at which product requirements are prescribed in an organization's buying decision process is known as need specification. This stage follows need identification and involves detailing the specific requirements that the product must meet.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>10", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "INTERNATIONAL MARKETING : INFLUENCING FACTORS", "question": "A reason for engaging in international marketing by a company is to", "images": [], "options": {"A": "utilize excess capacity", "B": "expand the national market", "C": "estimate the company's market share", "D": "forecast demand for company's product"}, "answer": "A", "explanation": "One reason for engaging in international marketing is to utilize excess capacity. Companies may have production capabilities that exceed domestic demand, and by entering international markets, they can increase their sales and make better use of their resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>11", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "Which of the following activities would a company embark upon to solve an identified marketing problem? Marketing", "images": [], "options": {"A": "planning", "B": "research", "C": "objectives", "D": "intelligence"}, "answer": "B", "explanation": "The correct answer is 'research'. Companies conduct research to identify and understand marketing problems, which allows them to develop effective strategies to address those issues.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>12", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "A series of activities that lead to marketing objectives setting is", "images": [], "options": {"A": "sales plan", "B": "market plan", "C": "market planning", "D": "marketing survey"}, "answer": "C", "explanation": "The correct answer is 'market planning'. Market planning involves a series of activities that lead to the setting of marketing objectives, including analysis of market conditions and the development of strategies to achieve those objectives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>13", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "Marketing survey is carried out purposely to", "images": [], "options": {"A": "sell a product", "B": "collect information", "C": "improve a company's image", "D": "promote a new course"}, "answer": "B", "explanation": "The correct answer is 'collect information'. A marketing survey is specifically designed to gather data and insights about consumer preferences, market trends, and other relevant information that can inform marketing strategies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>14", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "ADVERTISING : FUNCTIONS", "question": "The form of advertising which aims at stimulating the demand for a particular brand of product is", "images": [], "options": {"A": "competitive advertising", "B": "generic advertising", "C": "informative advertising", "D": "persuassive advertising"}, "answer": "D", "explanation": "The correct answer is 'persuasive advertising'. This type of advertising aims to stimulate demand for a specific brand by convincing consumers of its benefits and advantages over competitors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>15", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "A voucher received by Adam for a product bought at A. A. stores that qualifies him for a price reduction in a repeat purchase is", "images": [], "options": {"A": "premium", "B": "contest", "C": "sweepstakes", "D": "coupon"}, "answer": "D", "explanation": "The correct answer is 'coupon'. A coupon is a voucher that provides a discount on a future purchase, incentivizing repeat business from customers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>16", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "Premium offers and coupons are elements of", "images": [], "options": {"A": "personal selling tools", "B": "direct marketing tools", "C": "sales promotional tools", "D": "advertising tools"}, "answer": "C", "explanation": "Premium offers and coupons are considered sales promotional tools because they are designed to stimulate consumer purchases and increase sales in the short term. Sales promotions are marketing strategies that provide added value to the consumer, encouraging them to buy a product or service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>17", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MERCHANDISING : FUNCTIONS", "question": "In-store and window displays are elements of", "images": [], "options": {"A": "sales contest", "B": "trade-in-allowance", "C": "free samples", "D": "merchandising"}, "answer": "D", "explanation": "In-store and window displays are elements of merchandising. Merchandising involves the presentation of products in a retail environment to maximize sales. Effective merchandising can attract customers and enhance their shopping experience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>18", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : INFLUECING FACTORS", "question": "A psychological factor that influences consumer buying behaviour is", "images": [], "options": {"A": "social class", "B": "cultural trend", "C": "family", "D": "perception"}, "answer": "D", "explanation": "Perception is a psychological factor that influences consumer buying behavior. It refers to the process by which individuals select, organize, and interpret information to form a meaningful picture of the world. This can significantly affect how consumers view products and brands.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>19", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "A distribution channel member that would be used by a company that manufacturers heavy drilling equipment is", "images": [], "options": {"A": "broker", "B": "dealer", "C": "wholesaler", "D": "retailer"}, "answer": "C", "explanation": "A wholesaler would be a distribution channel member used by a company that manufactures heavy drilling equipment. Wholesalers purchase large quantities of goods from manufacturers and sell them to retailers or other businesses, making them suitable for distributing heavy equipment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>20", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "TRANSPORTATION : MEANING,MODE, CHOICE AND IMPORTANCE", "question": "Which of these transportation modes is suitable for transporting gas from Banjul to Brikama?", "images": [], "options": {"A": "Rail", "B": "Pipeline", "C": "Air", "D": "Water"}, "answer": "B", "explanation": "Pipeline is the most suitable transportation mode for transporting gas from Banjul to Brikama. Pipelines are specifically designed for the efficient and safe transport of liquids and gases over long distances, making them ideal for this purpose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>21", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "TRANSPORTATION : DOCUMENTS USED IN TRANSPORTATION", "question": "A transportation document that indicates the quantity and place of delivery of goods is", "images": [], "options": {"A": "waybill", "B": "invoice", "C": "receipt", "D": "manifest"}, "answer": "D", "explanation": "A transportation document that indicates the quantity and place of delivery of goods is called a 'manifest'. A manifest is a comprehensive list of the cargo being transported, detailing the items, their quantities, and their destination.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>22", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "WAREHOUSING : MEANING, TYPES AND DEFINITIONS", "question": "Which of the following individuals makes use of warehouse?", "images": [], "options": {"A": "The final consumer", "B": "An advertising agent", "C": "A wholesaler", "D": "A broker"}, "answer": "C", "explanation": "A wholesaler makes use of a warehouse to store large quantities of goods before distributing them to retailers or other businesses. Wholesalers buy in bulk and require storage facilities to manage their inventory.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>23", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "DISTRIBUTION : CHANNES OF DISTRIBUTION", "question": "Who among the following members comes first in the channel of distribution?", "images": [], "options": {"A": "Retailer", "B": "Consumer", "C": "Manufacturer", "D": "Wholesaler"}, "answer": "C", "explanation": "The manufacturer comes first in the channel of distribution. They produce the goods and are the starting point in the supply chain, followed by wholesalers, retailers, and finally consumers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>24", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING", "question": "The aspect of a marketing plan that specifies the main goals and recommendations is the", "images": [], "options": {"A": "action programmes", "B": "budgets", "C": "executive summary", "D": "objectives"}, "answer": "D", "explanation": "The aspect of a marketing plan that specifies the main goals and recommendations is referred to as 'objectives'. Objectives outline what the marketing plan aims to achieve and guide the overall strategy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>25", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKET UNIONS AND FACILITATORS : MARKET UNIONS MEANING AND TYPES", "question": "Beans Sellers Association is an example of", "images": [], "options": {"A": "cartel", "B": "market union", "C": "trade union", "D": "labour union"}, "answer": "C", "explanation": "Beans Sellers Association is an example of a 'trade union'. Trade unions are organizations that represent the interests of workers in a specific industry, advocating for their rights and benefits.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>26", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "ENTREPRENUERSHIP IN MARKETING : SOURCES OF FUNDS", "question": "Funds source by a baker from previous year's profit for expansion is", "images": [], "options": {"A": "personal savings", "B": "bank loan", "C": "bank overdraft", "D": "retained earning"}, "answer": "D", "explanation": "The funds sourced by a baker from previous year's profit for expansion is known as retained earnings. Retained earnings are the portion of net income that is retained in the company rather than being paid out as dividends. This is a common practice for businesses looking to reinvest in their operations.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>27", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : MEANING", "question": "A Ministry of Education (MOE) that procures stationery for public school's use, is an example of", "images": [], "options": {"A": "reseller market", "B": "consumer market", "C": "government market", "D": "industrial market"}, "answer": "C", "explanation": "A Ministry of Education (MOE) that procures stationery for public school's use is an example of a government market. Government markets involve the purchase of goods and services by government entities for public use, which distinguishes them from consumer and industrial markets.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>28", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : MEANING OF MARKETING MIX", "question": "The combination of variables such as product, place, price and promotion constitute the", "images": [], "options": {"A": "promotional mix", "B": "marketing mix", "C": "distribution mix", "D": "product mix"}, "answer": "B", "explanation": "The combination of variables such as product, place, price, and promotion constitutes the marketing mix. The marketing mix is a foundational concept in marketing that outlines the key elements that a company can control to influence consumer purchasing decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>29", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : INFLUECING FACTORS", "question": "Use the following information to answer the question    Johnson and Bitwa Ltd is into the production of soya beans milk. The business is  located at the outskirts of the city and is experiencing low patronage.    Which of the following factors could have resulted to the low demand of the product?", "images": [], "options": {"A": "Government tax", "B": "Availability of infrastructures", "C": "Proximity to the market", "D": "Increasing production output"}, "answer": "A", "explanation": "The low demand for Johnson and Bitwa Ltd's soya beans milk could be influenced by government tax. High taxes can increase the cost of production or the final price of the product, leading to reduced demand. Other factors like availability of infrastructure and proximity to the market are also relevant, but government tax is a direct economic factor affecting demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>30", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETING PLANNING AND RESEARCH : UTILIZATION OF FEEDBACK", "question": "Use the following information to answer the question    Johnson and Bitwa Ltd is into the production of soya beans milk. The business is  located at the outskirts of the city and is experiencing low patronage.    The company can increase the sales of its products by", "images": [], "options": {"A": "offering delivery services to customers", "B": "increasing production output", "C": "reducing personnel costs", "D": "diversifying sources of raw materials"}, "answer": "A", "explanation": "The company can increase the sales of its products by offering delivery services to customers. This strategy can enhance customer convenience and accessibility, potentially leading to increased sales. While other options may have some merit, offering delivery directly addresses the issue of low patronage by making the product more accessible.", "marks": "1", "difficulty": "2"}, {"id": "objective>Marketing>2025>31", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "SALES PROMOTION : MEANING AND FUNCTIONS", "question": "A sales promotional tool aimed at encouraging stocking of products by sellers is", "images": [], "options": {"A": "free samples", "B": "quantity discount", "C": "patronage reward", "D": "free gifts"}, "answer": "B", "explanation": "A quantity discount is a sales promotional tool that encourages sellers to stock more products by offering them a discount based on the quantity purchased. This incentivizes retailers to buy larger quantities, thus promoting the product's availability in the market.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>32", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "WAREHOUSING : MEANING, TYPES AND DEFINITIONS", "question": "Which of the following activities is not performed in a warehouse?", "images": [], "options": {"A": "Designing of products", "B": "Storage of products", "C": "Sorting of products", "D": "Packaging of products"}, "answer": "A", "explanation": "Designing of products is not a warehouse activity. Warehouses are primarily involved in storage, sorting, and packaging of products. Designing is a part of product development, which occurs before the product reaches the warehouse.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>33", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "DISTRIBUTION : FUNCTIONS", "question": "The breaking of bulk is a function of the", "images": [], "options": {"A": "broker", "B": "agent", "C": "wholesaler", "D": "sales force"}, "answer": "C", "explanation": "The breaking of bulk is a function of the wholesaler. Wholesalers purchase large quantities of goods from manufacturers and break them down into smaller quantities for resale to retailers. This process helps in making products more accessible to smaller retailers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>34", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETS : CLASSIFICATION", "question": "Which of the following activities is not a feature of industrial market?", "images": [], "options": {"A": "Goods are bought through specialists", "B": "Customers are rational in product selection", "C": "Goods are bought for production purposes", "D": "Goods are bought for final consumption"}, "answer": "D", "explanation": "Goods bought for final consumption is not a feature of the industrial market. The industrial market primarily involves goods purchased for production purposes, while goods bought for final consumption are characteristic of the consumer market.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>35", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "ADVERTISING : MEDIA - MEANING, TYPES, ADVATAGES AND DISADVANTAGES", "question": "An advertising media that has a wider coverage at a lower cost to advertise is", "images": [], "options": {"A": "television", "B": "radio", "C": "magazine", "D": "journal"}, "answer": "B", "explanation": "Radio is an advertising medium that offers wider coverage at a lower cost compared to other media like television, magazines, or journals. It can reach a large audience quickly and is often more cost-effective for advertisers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>36", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "MARKETING MIX AND MARKETING ENVIRONMENT : MARKETING ENVIRONMENT", "question": "The component of the marketing environment that deals with the traditions and norms of the  society is", "images": [], "options": {"A": "political factors", "B": "technological factors", "C": "cultural factors", "D": "economic factors"}, "answer": "C", "explanation": "The component of the marketing environment that deals with the traditions and norms of society is known as cultural factors. Cultural factors include values, beliefs, and customs that influence consumer behavior and marketing strategies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>37", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "PRODUCTS : MEANING", "question": "An idea offered for sale is", "images": [], "options": {"A": "promotion", "B": "price", "C": "product", "D": "place"}, "answer": "C", "explanation": "An idea offered for sale is referred to as a product. In marketing, a product can be a tangible good, a service, or an idea that satisfies a need or want.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>38", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "The starting point of the buyer decision making process is", "images": [], "options": {"A": "information search", "B": "evaluation of alternatives", "C": "problem recognition", "D": "purchase decision"}, "answer": "C", "explanation": "The starting point of the buyer decision-making process is problem recognition. This is when a consumer identifies a need or a problem that requires a solution, prompting them to seek out information and alternatives.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>39", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "CONSUMER AND ORGANIZATIONAL BEHAVIOUR : DECISION PROCESS IN LOGICAL ORDER", "question": "Which of the following stages is the last in consumer buying decision making process?", "images": [], "options": {"A": "Need recognition", "B": "Purchase decision", "C": "Post purchase behaviour", "D": "Evaluation of alternatives"}, "answer": "C", "explanation": "The last stage in the consumer buying decision-making process is post-purchase behavior. This stage involves the consumer's evaluation of their purchase, which can affect future buying decisions and brand loyalty.", "marks": "1", "difficulty": "1"}, {"id": "objective>Marketing>2025>40", "subject": "Marketing", "year": "2025", "type": "Objective", "topic": "DISTRIBUTION : FUNCTIONS", "question": "The marketing function that involves the movement of goods to the target market is", "images": [], "options": {"A": "warehousing", "B": "distribution", "C": "pricing", "D": "promotion"}, "answer": "B", "explanation": "The marketing function that involves the movement of goods to the target market is distribution. Distribution encompasses all the activities required to get the product from the manufacturer to the consumer, including logistics and supply chain management.", "marks": "1", "difficulty": "1"}];